// ============================================================
// ESTADO
// ============================================================
const S = { desde: '', hasta: '', cluster: '', cliente: '', snap: 'mes_actual' };
let chartCanal = null, chartMarca = null, chartEvol = null;
let activeTab = 'general', S_bosque_prod = '';
let chartBosqueEvol = null, chartBosqueClientes = null;

// ============================================================
// INICIALIZACIÓN
// ============================================================
(function init() {
  // Poblar select de clusterización (dinámico)
  const clusters = [...new Set(ROWS.map(r => r.cl))].sort();
  const csel = document.getElementById('f-cluster');
  clusters.forEach(cl => {
    const o = document.createElement('option');
    o.value = cl; o.textContent = cl;
    csel.appendChild(o);
  });

  // Poblar select de clientes
  const clientes = [...new Set(ROWS.map(r => r.nd))].sort();
  const sel = document.getElementById('f-cliente');
  clientes.forEach(nd => {
    const o = document.createElement('option');
    o.value = nd; o.textContent = nd;
    sel.appendChild(o);
  });

  // Período inicial: mes actual
  setSnap('mes_actual', document.querySelector('#snap-btns .fb'));
})();

// ============================================================
// FILTROS
// ============================================================
function setSnap(snap, btn) {
  S.snap = snap;
  const today = new Date();
  const y = today.getFullYear(), m = today.getMonth();
  let d0, d1;
  if (snap === 'mes_actual') {
    d0 = new Date(y, m, 1);
    d1 = today;
  } else if (snap === 'mes_anterior') {
    d0 = new Date(y, m - 1, 1);
    d1 = new Date(y, m, 0);
  } else if (snap === 'ytd') {
    d0 = new Date(y, 0, 1);
    d1 = today;
  } else if (snap === 'ultimos_3m') {
    d0 = new Date(y, m - 3, 1);
    d1 = today;
  } else {
    d0 = new Date('2024-01-01');
    d1 = today;
  }
  S.desde = fmt(d0);
  S.hasta = fmt(d1);
  document.getElementById('f-desde').value = S.desde;
  document.getElementById('f-hasta').value = S.hasta;
  activateSnap(btn);
  applyFilters();
}

function setCustom() {
  S.desde = document.getElementById('f-desde').value;
  S.hasta = document.getElementById('f-hasta').value;
  S.snap = 'custom';
  activateSnap(null);
  applyFilters();
}

function setCluster(cl) {
  S.cluster = cl;
  applyFilters();
}

function clearFilters() {
  S.cluster = '';
  S.cliente = '';
  S_bosque_prod = '';
  document.getElementById('f-cluster').value = '';
  document.getElementById('f-cliente').value = '';
  const bf = document.getElementById('bos-prod-filter');
  if (bf) bf.value = '';
  setSnap('mes_actual', document.querySelector('#snap-btns .fb'));
}

function activateSnap(btn) {
  document.querySelectorAll('#snap-btns .fb').forEach(b => b.classList.remove('active'));
  if (btn) btn.classList.add('active');
}

// ============================================================
// FILTRADO DE DATOS
// ============================================================
function getRows(desdeOverride, hastaOverride) {
  const d0 = desdeOverride || S.desde;
  const d1 = hastaOverride || S.hasta;
  return ROWS.filter(r => {
    if (d0 && r.f < d0) return false;
    if (d1 && r.f > d1) return false;
    if (S.cluster && r.cl !== S.cluster) return false;
    if (S.cliente && r.nd !== S.cliente) return false;
    return true;
  });
}

function getYoYRange() {
  if (!S.desde && !S.hasta) return { d0: '', d1: '' };
  const shift = d => d ? shiftYear(d, -1) : '';
  return { d0: shift(S.desde), d1: shift(S.hasta) };
}

function getPrevPeriodRange() {
  // Período anterior: misma duración, termina el día antes que empieza el actual
  if (!S.desde || !S.hasta) return { d0: '', d1: '' };
  const msDay = 86400000;
  const d0 = new Date(S.desde + 'T00:00:00');
  const d1 = new Date(S.hasta + 'T00:00:00');
  const days = Math.round((d1 - d0) / msDay); // duración en días
  const prevD1 = new Date(d0 - msDay);
  const prevD0 = new Date(prevD1 - days * msDay);
  return { d0: fmt(prevD0), d1: fmt(prevD1) };
}

function shiftYear(dateStr, dy) {
  if (!dateStr) return '';
  const parts = dateStr.split('-');
  return `${+parts[0] + dy}-${parts[1]}-${parts[2]}`;
}

function agg(rows) {
  let ce = 0, li = 0, to = 0;
  rows.forEach(r => { ce += r.ce; li += r.li; to += r.to; });
  return { ce, li, to };
}

function byKey(rows, key) {
  const out = {};
  rows.forEach(r => {
    const k = r[key] || '(vacío)';
    if (!out[k]) out[k] = { ce: 0, li: 0, to: 0 };
    out[k].ce += r.ce;
    out[k].li += r.li;
    out[k].to += r.to;
  });
  return out;
}

function byMonth(rows) {
  const out = {};
  rows.forEach(r => {
    const ym = r.f.substring(0, 7);
    if (!out[ym]) out[ym] = { ce: 0, li: 0, to: 0 };
    out[ym].ce += r.ce;
    out[ym].li += r.li;
    out[ym].to += r.to;
  });
  return out;
}

// ── Comparación dinámica según preset ────────────────────────
function getCompareRows() {
  const pop = getPrevPeriodRange();
  const yoy = getYoYRange();
  const cfg = {
    mes_actual:   { range: pop, label: 'mes ant.' },
    mes_anterior: { range: yoy, label: 'mismo mes aa' },
    ytd:          { range: yoy, label: 'YTD aa' },
    ultimos_3m:   { range: yoy, label: '3M aa' },
    todo:         { range: pop, label: 'per. ant.' },
    custom:       { range: pop, label: 'per. ant.' },
  };
  const { range, label } = cfg[S.snap] || cfg.custom;
  return { rows: getRows(range.d0, range.d1), label };
}

// ============================================================
// RENDER PRINCIPAL
// ============================================================
function applyFilters() {
  if (S.cliente !== document.getElementById('f-cliente').value) {
    S.cliente = document.getElementById('f-cliente').value;
  }

  const rows    = getRows();
  const yoy     = getYoYRange();
  const rowsYoY = getRows(yoy.d0, yoy.d1);
  const pop     = getPrevPeriodRange();
  const rowsPop = getRows(pop.d0, pop.d1);

  const cur   = agg(rows);
  const prv   = agg(rowsYoY);
  const popAg = agg(rowsPop);

  const rLabel = S.desde && S.hasta
    ? `${fmtDisp(S.desde)} → ${fmtDisp(S.hasta)}`
    : 'Todo el período';
  document.getElementById('footer-rango').textContent = rLabel;

  if (activeTab === 'feriado-tabla') {
    renderFeriadoTabla(rows);
    renderFeriadoSemanas(rows);
  } else if (activeTab === 'feriado') {
    renderFeriadoTab(rows, rowsYoY, rowsPop);
  } else if (activeTab === 'bosque') {
    renderBosqueTab(rows, rowsYoY, rowsPop);
  } else if (activeTab === 'bosque-tabla') {
    renderBosqueTabla(rows);
  } else if (activeTab === 'bosque-semanas') {
    renderBosqueSemanasTabla(rows);
  } else if (activeTab === 'bosque-precio') {
    renderBosquePrecio(rows, rowsPop);
    renderBosqueClientesSemana(rows);
  } else if (activeTab === 'feriado-precio') {
    const cmp = getCompareRows();
    renderFeriadoPrecio(rows, rowsPop, 'per. ant.');
    renderFeriadoClientesSemana(rows);
  } else if (activeTab === 'cerveza') {
    renderCervezaTab(rows, rowsYoY, rowsPop);
  } else {
    renderKPIs(cur, prv, popAg);
    renderBosqueFeriado(rows, rowsYoY, rowsPop);
    renderLataPanel(rows, rowsYoY, rowsPop);
    renderClusterTable(rows, rowsPop);
    renderCharts(rows, rowsYoY);
  }
}

// ============================================================
// KPIs
// ============================================================
function renderKPIs(cur, prv, pop) {
  setKPI('kpi-fac', cur.to, prv.to, pop.to, '', true);
  setKPI('kpi-env', cur.ce, prv.ce, pop.ce, '',  false);
  setKPI('kpi-lit', cur.li, prv.li, pop.li, '',  false, 1);
}

function setKPI(id, val, yoyVal, popVal, prefix, isMoney, dec) {
  dec = dec || 0;
  document.getElementById(id).textContent = prefix + fmtNum(val, dec, isMoney);
  setBadge(id + '-yoy', val, yoyVal, 'aa');
  setBadge(id + '-pop', val, popVal, 'pa');
}

function setBadge(elId, val, ref, lbl) {
  const el = document.getElementById(elId);
  if (!el) return;
  if (!ref || ref === 0) { el.textContent = '—'; el.className = 'badge neu'; return; }
  const pct = ((val - ref) / Math.abs(ref)) * 100;
  el.textContent = (pct >= 0 ? '+' : '') + pct.toFixed(1) + '% ' + lbl;
  el.className = 'badge ' + (pct >= 0 ? 'up' : 'dn');
}

// ============================================================
// HELPER: actualizar una fila de panel
// ============================================================
function setPanelRow(slug, val, yoyVal, popVal, total, dec) {
  dec = (dec === undefined) ? 1 : dec;
  const elV = document.getElementById('val-' + slug);
  if (elV) elV.textContent = fmtNum(val, dec);
  const elS = document.getElementById('share-' + slug);
  if (elS) elS.textContent = total > 0 ? (val/total*100).toFixed(0)+'%' : '';
  const elP = document.getElementById('pct-' + slug);
  if (elP) {
    const yoyTxt = pctYoY(val, yoyVal);
    const popTxt = pctYoY(val, popVal);
    const yoyClr = yoyTxt.startsWith('+') ? '#6ee7b7' : (yoyTxt && !yoyTxt.includes('—') ? '#fca5a5' : '#6e7681');
    const popClr = popTxt.startsWith('+') ? '#60a5fa' : (popTxt && !popTxt.includes('—') ? '#fca5a5' : '#6e7681');
    elP.style.minWidth = '62px';
    elP.innerHTML =
      `<span style="color:${yoyClr};font-weight:700">${yoyTxt||'—'} <span style="font-size:9px;opacity:.65">aa</span></span>` +
      `<br><span style="color:${popClr};font-weight:700">${popTxt||'—'} <span style="font-size:9px;opacity:.65">pa</span></span>`;
  }
  const elB = document.getElementById('bar-' + slug);
  if (elB) {
    const w = total > 0 ? (val/total*100).toFixed(1)+'%' : '0%';
    requestAnimationFrame(() => requestAnimationFrame(() => { elB.style.width = w; }));
  }
}

// ============================================================
// PANELES BOSQUE / FERIADO / LATA
// ============================================================
function renderBosqueFeriado(rows, rowsYoY, rowsPop) {
  const fa    = byKey(rows,    'fa');
  const faYoY = byKey(rowsYoY, 'fa');
  const faPop = byKey(rowsPop, 'fa');

  // — Bosque — litros
  const bKeys  = ['bosque_nativo','bosque_alta_montana','bosque_refugios','bosque_otro'];
  const bTotal = bKeys.reduce((s,k) => s + (fa[k]?.li || 0), 0);
  document.getElementById('bosque-total').textContent = fmtNum(bTotal, 1);

  const bSlug = { bosque_nativo:'bosque-nativo', bosque_alta_montana:'bosque-alta_montana',
                  bosque_refugios:'bosque-refugios', bosque_otro:'bosque-otro' };
  bKeys.forEach(k => setPanelRow(bSlug[k], fa[k]?.li||0, faYoY[k]?.li||0, faPop[k]?.li||0, bTotal));

  // — Feriado — litros
  const fKeys  = ['feriado_rojo','feriado_rosado','feriado_barril_20','feriado_barril_50'];
  const fTotal = fKeys.reduce((s,k) => s + (fa[k]?.li || 0), 0);
  document.getElementById('feriado-total').textContent = fmtNum(fTotal, 1);

  // Barril = suma de 20LT + 50LT
  const barrilLi    = (fa['feriado_barril_20']?.li||0) + (fa['feriado_barril_50']?.li||0);
  const barrilLiYoY = (faYoY['feriado_barril_20']?.li||0) + (faYoY['feriado_barril_50']?.li||0);
  const barrilLiPop = (faPop['feriado_barril_20']?.li||0) + (faPop['feriado_barril_50']?.li||0);
  setPanelRow('feriado-rojo',   fa['feriado_rojo']?.li||0,   faYoY['feriado_rojo']?.li||0,   faPop['feriado_rojo']?.li||0,   fTotal);
  setPanelRow('feriado-rosado', fa['feriado_rosado']?.li||0, faYoY['feriado_rosado']?.li||0, faPop['feriado_rosado']?.li||0, fTotal);
  setPanelRow('feriado-barril', barrilLi, barrilLiYoY, barrilLiPop, fTotal);
}

// ============================================================
// PANEL CERVEZA LATA
// ============================================================
function renderLataPanel(rows, rowsYoY, rowsPop) {
  const fa    = byKey(rows,    'fa');
  const faYoY = byKey(rowsYoY, 'fa');
  const faPop = byKey(rowsPop, 'fa');

  const lataKeys  = ['lata_wolf','lata_scottish','lata_golden','lata_wolf0','lata_otras'];
  const lataTotal = lataKeys.reduce((s,k) => s + (fa[k]?.li || 0), 0);
  document.getElementById('lata-total').textContent = fmtNum(lataTotal, 1);

  const slugMap = {
    lata_wolf:'lata-wolf', lata_scottish:'lata-scottish',
    lata_golden:'lata-golden', lata_wolf0:'lata-wolf0', lata_otras:'lata-otras'
  };
  lataKeys.forEach(k => setPanelRow(slugMap[k], fa[k]?.li||0, faYoY[k]?.li||0, faPop[k]?.li||0, lataTotal));
}

// ============================================================
// TABLA CLUSTERIZACIÓN
// ============================================================
function renderClusterTable(rows, rowsPop) {
  const data    = byKey(rows,    'cl');
  const dataPop = byKey(rowsPop, 'cl');

  // Ordenar por envases desc
  const sorted  = Object.entries(data).sort((a,b) => b[1].ce - a[1].ce);
  const totCe   = sorted.reduce((s,[,v]) => s + v.ce, 0);
  const totLi   = sorted.reduce((s,[,v]) => s + v.li, 0);
  const totPop  = Object.values(dataPop).reduce((s,v) => s + v.ce, 0);

  const tbody = document.getElementById('tbl-cluster-body');
  tbody.innerHTML = '';

  sorted.forEach(([cl, v]) => {
    const prevCe = dataPop[cl]?.ce || 0;
    const tr = document.createElement('tr');
    tr.innerHTML = `
      <td>${cl}</td>
      <td>${fmtNum(v.ce)}</td>
      <td>${fmtNum(v.li, 1)}</td>
      <td>${pctYoYCell(v.ce, prevCe)}</td>
    `;
    tbody.appendChild(tr);
  });

  // Fila total
  const trT = document.createElement('tr');
  trT.className = 'total-row';
  trT.innerHTML = `
    <td>Total</td>
    <td>${fmtNum(totCe)}</td>
    <td>${fmtNum(totLi, 1)}</td>
    <td>${pctYoYCell(totCe, totPop)}</td>
  `;
  tbody.appendChild(trT);
}

// ============================================================
// GRÁFICOS
// ============================================================
function renderCharts(rows, rowsYoY) {
  loadChartJS(function() {
    if (typeof Chart === 'undefined') return;
    renderCanalChart(rows);
    renderMarcaChart(rows);
    renderEvolChart(rows, rowsYoY);
  });
}

const PALETTE = [
  '#c9a227','#a78bfa','#6ee7b7','#38bdf8','#f59e0b',
  '#f472b6','#34d399','#818cf8','#fbbf24','#60a5fa',
  '#4ade80','#e879f9','#94a3b8'
];

function renderCanalChart(rows) {
  const data   = byKey(rows, 'cl');
  const sorted = Object.entries(data).sort((a,b) => b[1].ce - a[1].ce).slice(0, 12);
  const labels = sorted.map(([k]) => k);
  const envases = sorted.map(([,v]) => v.ce);
  const totEnv  = envases.reduce((a,b) => a+b, 0);

  if (chartCanal) chartCanal.destroy();
  chartCanal = new Chart(document.getElementById('chart-canal'), {
    type: 'bar',
    data: {
      labels,
      datasets: [{
        label: 'Envases',
        data: envases,
        backgroundColor: sorted.map((_,i) => PALETTE[i % PALETTE.length] + 'cc'),
        borderColor:     sorted.map((_,i) => PALETTE[i % PALETTE.length]),
        borderWidth: 1,
        borderRadius: 4,
      }]
    },
    options: {
      indexAxis: 'y',
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: { display: false },
        tooltip: {
          callbacks: {
            label: ctx => {
              const pct = totEnv > 0 ? (ctx.raw / totEnv * 100).toFixed(1) : '0';
              return ` ${fmtNum(ctx.raw)} env. · ${pct}% del total`;
            }
          }
        }
      },
      scales: {
        x: {
          ticks: { color:'#8b949e', font:{size:10},
            callback: v => v >= 1000 ? (v/1000).toFixed(0)+'k' : v
          },
          grid: { color:'rgba(48,54,61,.5)' }
        },
        y: {
          ticks: { color:'#c9d1d9', font:{size:10} },
          grid:  { display: false }
        }
      }
    }
  });
}

function renderMarcaChart(rows) {
  const fa = byKey(rows, 'fa');

  const bosqueEnv  = ['bosque_nativo','bosque_alta_montana','bosque_refugios','bosque_otro'].reduce((s,k)=>s+(fa[k]?.ce||0),0);
  const feriadoEnv = ['feriado_rojo','feriado_rosado','feriado_barril_20','feriado_barril_50'].reduce((s,k)=>s+(fa[k]?.ce||0),0);
  const merchEnv   = fa['merch']?.ce || 0;

  const bosqueLit  = ['bosque_nativo','bosque_alta_montana','bosque_refugios','bosque_otro'].reduce((s,k)=>s+(fa[k]?.li||0),0);
  const feriadoLit = ['feriado_rojo','feriado_rosado','feriado_barril_20','feriado_barril_50'].reduce((s,k)=>s+(fa[k]?.li||0),0);
  const merchLit   = fa['merch']?.li || 0;

  const labels  = ['Bosque','Feriado','Merch'];
  const colors  = ['#6ee7b7','#f59e0b','#a78bfa'];
  const colorBg = ['#6ee7b799','#f59e0b99','#a78bfa99'];

  if (chartMarca) chartMarca.destroy();
  chartMarca = new Chart(document.getElementById('chart-marca'), {
    type: 'bar',
    data: {
      labels,
      datasets: [
        {
          label: 'Envases',
          data: [bosqueEnv, feriadoEnv, merchEnv],
          backgroundColor: colorBg,
          borderColor: colors,
          borderWidth: 1,
          borderRadius: 4,
          yAxisID: 'yEnv',
        },
        {
          label: 'Litros',
          data: [bosqueLit, feriadoLit, merchLit],
          backgroundColor: colors.map(c => c + '44'),
          borderColor: colors.map(c => c + 'aa'),
          borderWidth: 1,
          borderRadius: 4,
          borderDash: [4,3],
          type: 'line',
          yAxisID: 'yLit',
          pointRadius: 5,
          pointHoverRadius: 7,
          tension: 0,
        }
      ]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: {
          labels: { color:'#c9d1d9', font:{size:10}, boxWidth:12,
            generateLabels: chart =>
              Chart.defaults.plugins.legend.labels.generateLabels(chart).map(l=>({...l,fontColor:'#c9d1d9'}))
          }
        },
        tooltip: { mode:'index', intersect:false }
      },
      scales: {
        yEnv: {
          type: 'linear', position: 'left',
          ticks: { color:'#8b949e', font:{size:10},
            callback: v => v >= 1000 ? (v/1000).toFixed(0)+'k' : v
          },
          grid: { color:'rgba(48,54,61,.4)' },
          title: { display:true, text:'Envases', color:'#6e7681', font:{size:9} }
        },
        yLit: {
          type: 'linear', position: 'right',
          ticks: { color:'#8b949e', font:{size:10},
            callback: v => v >= 1000 ? (v/1000).toFixed(0)+'k lts' : v+' lts'
          },
          grid: { display: false },
          title: { display:true, text:'Litros', color:'#6e7681', font:{size:9} }
        },
        x: {
          ticks: { color:'#c9d1d9', font:{size:11} },
          grid:  { display: false }
        }
      }
    }
  });
}

function renderEvolChart(rows, rowsYoY) {
  const bosqueKeys  = ['bosque_nativo','bosque_alta_montana','bosque_refugios',
                       'bosque_nativo_mini','bosque_alta_montana_mini','bosque_otro'];
  const feriadoKeys = ['feriado_rojo','feriado_rosado','feriado_barril_20','feriado_barril_50'];
  const cervezaKeys = ['lata_wolf','lata_scottish','lata_golden','lata_wolf0','lata_otras'];

  function byMonthBrand(rs) {
    const out = {};
    rs.forEach(r => {
      const ym = r.f.substring(0, 7);
      if (!out[ym]) out[ym] = { bosque: 0, feriado: 0, cerveza: 0, merch: 0 };
      if (bosqueKeys.includes(r.fa))       out[ym].bosque  += r.li;
      else if (feriadoKeys.includes(r.fa)) out[ym].feriado += r.li;
      else if (cervezaKeys.includes(r.fa)) out[ym].cerveza += r.li;
      else                                 out[ym].merch   += r.li;
    });
    return out;
  }

  const cur = byMonthBrand(rows);
  const prv = byMonth(rowsYoY);

  // Eje X = meses del período actual; línea YoY busca el mismo mes del año anterior
  const curYM = Object.keys(cur).sort();
  const lblFn = ym => {
    const [y,m] = ym.split('-');
    return ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'][+m-1]+' '+y.slice(2);
  };
  const prvFor = ym => { const [y,m] = ym.split('-'); return `${+y-1}-${m}`; };

  if (chartEvol) chartEvol.destroy();
  chartEvol = new Chart(document.getElementById('chart-evol'), {
    type: 'bar',
    data: {
      labels: curYM.map(lblFn),
      datasets: [
        {
          label: 'Bosque',
          data: curYM.map(ym => Math.round(cur[ym]?.bosque || 0)),
          backgroundColor: 'rgba(110,231,183,.85)',
          stack: 'cur', order: 2
        },
        {
          label: 'Feriado',
          data: curYM.map(ym => Math.round(cur[ym]?.feriado || 0)),
          backgroundColor: 'rgba(201,162,39,.85)',
          stack: 'cur', order: 2
        },
        {
          label: 'Cerveza',
          data: curYM.map(ym => Math.round(cur[ym]?.cerveza || 0)),
          backgroundColor: 'rgba(56,189,248,.85)',
          stack: 'cur', order: 2
        },
        {
          label: 'Merch',
          data: curYM.map(ym => Math.round(cur[ym]?.merch || 0)),
          backgroundColor: 'rgba(110,118,129,.5)',
          stack: 'cur', order: 2
        },
        {
          label: 'Año anterior',
          data: curYM.map(ym => Math.round(prv[prvFor(ym)]?.li || 0)),
          type: 'line',
          borderColor: 'rgba(148,163,184,.75)',
          backgroundColor: 'transparent',
          borderDash: [5, 4],
          borderWidth: 1.5,
          pointRadius: 2,
          pointHoverRadius: 5,
          tension: 0.3,
          order: 1
        }
      ]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      interaction: { mode: 'index', intersect: false },
      plugins: {
        legend: {
          position: 'top',
          align: 'end',
          labels: {
            color: '#8b949e', font: { size: 10 }, boxWidth: 10, padding: 8,
            generateLabels: function(chart) {
              return Chart.defaults.plugins.legend.labels.generateLabels(chart)
                .map(l => ({ ...l, fontColor: '#8b949e' }));
            }
          }
        },
        tooltip: {
          mode: 'index',
          intersect: false,
          backgroundColor: '#1c2128',
          borderColor: '#30363d',
          borderWidth: 1,
          titleColor: '#e6edf3',
          bodyColor: '#c9d1d9',
          footerColor: '#6ee7b7',
          footerFont: { weight: '700' },
          callbacks: {
            footer: function(items) {
              let stackTotal = 0, prevTotal = 0;
              items.forEach(i => {
                if (i.dataset.type === 'line') prevTotal = i.raw;
                else stackTotal += i.raw;
              });
              const lines = ['Total: ' + stackTotal.toLocaleString('es-AR') + ' L'];
              if (prevTotal > 0) {
                const pct = ((stackTotal - prevTotal) / prevTotal * 100);
                lines.push('vs año ant.: ' + (pct >= 0 ? '+' : '') + pct.toFixed(1) + '%');
              }
              return lines;
            }
          }
        }
      },
      scales: {
        x: {
          stacked: true,
          ticks: { color: '#8b949e', font: { size: 10 }, maxRotation: 40 },
          grid: { color: 'rgba(48,54,61,.4)' }
        },
        y: {
          stacked: true,
          ticks: {
            color: '#8b949e', font: { size: 10 },
            callback: v => v >= 1000 ? (v/1000).toFixed(0)+'k' : v
          },
          grid: { color: 'rgba(48,54,61,.4)' }
        }
      }
    }
  });
}

// ============================================================
// HELPERS
// ============================================================
function fmt(d) {
  return d.toISOString().split('T')[0];
}
function fmtDisp(s) {
  if (!s) return '';
  const [y,m,d] = s.split('-');
  return `${d}/${m}/${y}`;
}
function fmtNum(v, dec, isMoney) {
  dec = dec ?? 0;
  if (isMoney) {
    if (Math.abs(v) >= 1e6)  return '$'+(v/1e6).toFixed(1)+'M';
    if (Math.abs(v) >= 1e3)  return '$'+(v/1e3).toFixed(0)+'K';
    return '$'+Math.round(v).toLocaleString('es-AR');
  }
  if (dec === 0) return Math.round(v).toLocaleString('es-AR');
  return v.toFixed(dec).replace(/\B(?=(\d{3})+(?!\d))/g,',');
}
function pctYoY(cur, prv) {
  if (prv === 0) return '';
  const p = ((cur - prv) / Math.abs(prv)) * 100;
  return (p >= 0 ? '+' : '') + p.toFixed(1) + '% YoY';
}
function pctYoYCell(cur, prv) {
  if (prv === 0) return '<span class="pct-na">—</span>';
  const p = ((cur - prv) / Math.abs(prv)) * 100;
  const cls = p >= 0 ? 'pct-up' : 'pct-dn';
  return `<span class="${cls}">${p>=0?'+':''}${p.toFixed(1)}%</span>`;
}

// ============================================================
// TAB SWITCHING
// ============================================================
function switchTab(tab) {
  activeTab = tab;
  document.getElementById('view-general').style.display      = tab === 'general'       ? 'block' : 'none';
  document.getElementById('view-feriado').style.display       = tab === 'feriado'        ? 'block' : 'none';
  document.getElementById('view-feriado-tabla').style.display = tab === 'feriado-tabla'  ? 'block' : 'none';
  document.getElementById('view-bosque').style.display       = tab === 'bosque'        ? 'block' : 'none';
  document.getElementById('view-bosque-tabla').style.display   = tab === 'bosque-tabla'    ? 'block' : 'none';
  document.getElementById('view-bosque-semanas').style.display = tab === 'bosque-semanas' ? 'block' : 'none';
  document.getElementById('view-bosque-precio').style.display  = tab === 'bosque-precio'  ? 'block' : 'none';
  document.getElementById('view-feriado-precio').style.display = tab === 'feriado-precio' ? 'block' : 'none';
  document.getElementById('view-cerveza').style.display        = tab === 'cerveza'         ? 'block' : 'none';
  const bosqueTab = tab === 'bosque-tabla' || tab === 'bosque-semanas' || tab === 'bosque-precio'
                 || tab === 'feriado' || tab === 'feriado-tabla' || tab === 'feriado-precio';
  document.getElementById('bos-prod-fg').style.display = bosqueTab ? 'flex' : 'none';
  // Standalone tabs
  document.querySelectorAll('.tab-btn').forEach(b =>
    b.classList.toggle('active', b.dataset.tab === tab));
  // Sub-menu items
  document.querySelectorAll('.tab-sub-btn').forEach(b =>
    b.classList.toggle('active', b.dataset.tab === tab));
  // Group button highlights when a child is active
  document.querySelectorAll('.tab-group').forEach(grp => {
    const childActive = [...grp.querySelectorAll('.tab-sub-btn')].some(b => b.dataset.tab === tab);
    grp.classList.toggle('active-grp', childActive);
  });
  applyFilters();
}

function toggleTabGroup(id) {
  const grp = document.getElementById(id);
  const wasOpen = grp.classList.contains('open');
  document.querySelectorAll('.tab-group').forEach(g => g.classList.remove('open'));
  if (!wasOpen) {
    grp.classList.add('open');
    // Mobile: fix dropdown below button to escape overflow-x:auto clipping
    if (window.innerWidth <= 640) {
      const menu = grp.querySelector('.tab-group-menu');
      const btn  = grp.querySelector('.tab-group-btn');
      const rect = btn.getBoundingClientRect();
      menu.classList.add('mobile-fixed');
      menu.style.top = (rect.bottom + 4) + 'px';
    }
  }
}
function closeTabGroup(id) {
  const grp = document.getElementById(id);
  if (grp) {
    grp.classList.remove('open');
    const menu = grp.querySelector('.tab-group-menu');
    if (menu) { menu.classList.remove('mobile-fixed'); menu.style.top = ''; }
  }
}
document.addEventListener('click', e => {
  if (!e.target.closest('.tab-group')) {
    document.querySelectorAll('.tab-group').forEach(g => {
      g.classList.remove('open');
      const m = g.querySelector('.tab-group-menu');
      if (m) { m.classList.remove('mobile-fixed'); m.style.top = ''; }
    });
  }
});

function setBosqueProducto(fa) {
  S_bosque_prod = fa;
  applyFilters();
}

// ============================================================
// BOSQUE TAB — RENDER PRINCIPAL
// ============================================================
// ============================================================
// FERIADO
// ============================================================
const FER_KEYS = ['feriado_rojo','feriado_rosado','feriado_barril_20','feriado_barril_50'];

const FER_PRODUCTS = [
  { fa:'feriado_rojo',      label:'Feriado Rojo',     color:'#e63950', kpiId:'fer-kpi-rojo',     subId:'fer-kpi-rojo-sub' },
  { fa:'feriado_rosado',    label:'Feriado Rosado',   color:'#f9a8b8', kpiId:'fer-kpi-rosado',   subId:'fer-kpi-rosado-sub' },
  { fa:'feriado_barril_50', label:'Rojo Barril 50LT', color:'#f59e0b', kpiId:'fer-kpi-barril50', subId:'fer-kpi-barril50-sub' },
  { fa:'feriado_barril_20', label:'Rojo Barril 20LT', color:'#d97706', kpiId:'fer-kpi-barril20', subId:'fer-kpi-barril20-sub' },
];

// ── Feriado · Litros por Mes (pivot colapsable) ───────────────
function renderFeriadoTabla(rows) {
  const tbl = document.getElementById('feriado-tabla-tbl');
  if (!tbl) return;
  tbl.innerHTML = '';

  const fRows = rows.filter(r => FER_KEYS.includes(r.fa));
  if (!fRows.length) {
    tbl.innerHTML = '<tr><td style="color:#8b949e;padding:20px" colspan="20">Sin datos para el período seleccionado.</td></tr>';
    return;
  }

  const meses = [...new Set(fRows.map(r => r.f.slice(0,7)))].sort().reverse();

  // tree: cl → nd → mes → sum(li)
  const tree = {};
  fRows.forEach(r => {
    const m = r.f.slice(0,7);
    if (!tree[r.cl]) tree[r.cl] = {};
    if (!tree[r.cl][r.nd]) tree[r.cl][r.nd] = {};
    tree[r.cl][r.nd][m] = (tree[r.cl][r.nd][m] || 0) + r.li;
  });

  // Totales globales por mes
  const colTot = {};
  let grandTotal = 0;
  meses.forEach(m => {
    colTot[m] = fRows.filter(r => r.f.slice(0,7) === m).reduce((s,r) => s + r.li, 0);
    grandTotal += colTot[m];
  });
  const maxVal = Math.max(1, ...Object.values(colTot));

  // Año-grupos
  const yearGroups = [];
  meses.forEach(m => {
    const y = m.slice(0,4);
    if (yearGroups.length && yearGroups[yearGroups.length-1].year === y)
      yearGroups[yearGroups.length-1].count++;
    else yearGroups.push({year:y, count:1});
  });

  const MNAMES = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
  const CL_W = '150px', ND_W = '185px';
  const sCL = `position:sticky;left:0;width:${CL_W};min-width:${CL_W};z-index:2;`;
  const sND = `position:sticky;left:${CL_W};width:${ND_W};min-width:${ND_W};z-index:2;`;

  // ── THEAD ─────────────────────────────────────────────────────
  const thead = document.createElement('thead');
  const tr1 = document.createElement('tr');

  // Th Clusterización (rowspan 2)
  const thCl = document.createElement('th');
  thCl.rowSpan = 2;
  thCl.style.cssText = `${sCL}position:sticky;top:0;background:#1a0408;z-index:7;color:#e8d5a3;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;padding:7px 10px;border-bottom:2px solid #4a0a16;text-align:left;border-right:1px solid #4a0a16;`;
  thCl.innerHTML = `<span id="fer-exp-all" style="display:inline-flex;align-items:center;justify-content:center;width:15px;height:15px;border:1px solid #4a0a16;border-radius:2px;margin-right:7px;font-size:11px;font-weight:900;color:#e8d5a3;background:#2d0810;vertical-align:middle;cursor:pointer;flex-shrink:0" title="Expandir/colapsar todo">−</span>Clusterización`;
  tr1.appendChild(thCl);

  // Th NombreDeFantasía (rowspan 2)
  const thNd = document.createElement('th');
  thNd.rowSpan = 2;
  thNd.style.cssText = `${sND}position:sticky;top:0;background:#1a0408;z-index:7;color:#e8d5a3;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;padding:7px 10px;border-bottom:2px solid #4a0a16;text-align:left;border-right:1px solid #4a0a16;`;
  thNd.textContent = 'NombreDeFantasía';
  tr1.appendChild(thNd);

  // Year groups
  yearGroups.forEach(g => {
    const th = document.createElement('th');
    th.colSpan = g.count;
    th.style.cssText = 'position:sticky;top:0;background:#2d0810;z-index:4;text-align:center;color:#e8d5a3;font-size:11px;font-weight:700;letter-spacing:1px;padding:5px 8px;border-bottom:1px solid #4a0a16;';
    th.textContent = g.year;
    tr1.appendChild(th);
  });

  // Th Total (rowspan 2)
  const thTot = document.createElement('th');
  thTot.rowSpan = 2;
  thTot.style.cssText = 'position:sticky;top:0;right:0;background:#2d0810;z-index:6;text-align:right;color:#e8d5a3;font-size:10px;font-weight:700;padding:7px 12px;border-bottom:2px solid #4a0a16;border-left:2px solid #4a0a16;white-space:nowrap;';
  thTot.textContent = 'Total';
  tr1.appendChild(thTot);
  thead.appendChild(tr1);

  const tr2 = document.createElement('tr');
  meses.forEach(m => {
    const th = document.createElement('th');
    th.style.cssText = 'position:sticky;top:29px;background:#1a0408;z-index:4;color:#e8a0ac;font-size:11px;padding:4px 10px;text-align:right;white-space:nowrap;border-bottom:2px solid #4a0a16;';
    th.textContent = MNAMES[parseInt(m.slice(5,7),10)-1];
    tr2.appendChild(th);
  });
  thead.appendChild(tr2);
  tbl.appendChild(thead);

  // ── TBODY ─────────────────────────────────────────────────────
  const tbody = document.createElement('tbody');
  const sortedCl = Object.keys(tree).sort((a,b) => {
    const s = k => meses.reduce((t,m) => t + Object.values(tree[k]).reduce((tt,nd) => tt+(nd[m]||0),0),0);
    return s(b)-s(a);
  });

  sortedCl.forEach(cl => {
    const nds = Object.keys(tree[cl]).sort((a,b) => {
      const totA = meses.reduce((s,m) => s+(tree[cl][a][m]||0),0);
      const totB = meses.reduce((s,m) => s+(tree[cl][b][m]||0),0);
      return totB-totA;
    });
    const clId = 'fert_'+cl.replace(/[^a-z0-9]/gi,'_');

    const clTotMes = {};
    let clTotAll = 0;
    meses.forEach(m => { clTotMes[m] = nds.reduce((s,nd)=>s+(tree[cl][nd][m]||0),0); clTotAll+=clTotMes[m]; });

    // ── Cluster header row ────────────────────────────────────
    const trCl = document.createElement('tr');
    trCl.dataset.open = '1';
    trCl.dataset.clId = clId;
    trCl.style.cursor = 'pointer';

    const tdCl1 = document.createElement('td');
    tdCl1.style.cssText = `${sCL}background:#1a0408;color:#e8d5a3;font-size:11px;font-weight:700;padding:7px 10px;border-bottom:1px solid #4a0a16;border-right:1px solid #4a0a16;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;`;
    tdCl1.innerHTML = `<span id="${clId}-tog" style="display:inline-flex;align-items:center;justify-content:center;width:14px;height:14px;border:1px solid #4a0a16;border-radius:2px;margin-right:7px;font-size:10px;font-weight:900;color:#e8d5a3;background:#2d0810;vertical-align:middle;flex-shrink:0">−</span>${cl}`;
    trCl.appendChild(tdCl1);

    const tdCl2 = document.createElement('td');
    tdCl2.style.cssText = `${sND}background:#1a0408;border-bottom:1px solid #4a0a16;border-right:1px solid #4a0a16;`;
    trCl.appendChild(tdCl2);

    meses.forEach(m => {
      const val = clTotMes[m] || 0;
      const td = document.createElement('td');
      td.style.cssText = 'text-align:right;padding:7px 10px;font-size:11px;font-weight:700;background:#1a0408;border-bottom:1px solid #4a0a16;white-space:nowrap;font-variant-numeric:tabular-nums;color:#e6edf3;';
      td.textContent = val > 0 ? fmtNum(val,1) : '—';
      if (val > 0) td.style.color = '#e6edf3'; else td.style.color = '#484f58';
      trCl.appendChild(td);
    });

    const tdClTot = document.createElement('td');
    tdClTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:7px 12px;font-size:11px;font-weight:800;color:#e8d5a3;background:#1a0408;border-bottom:1px solid #4a0a16;border-left:2px solid #4a0a16;white-space:nowrap;font-variant-numeric:tabular-nums;';
    tdClTot.textContent = fmtNum(clTotAll,1);
    trCl.appendChild(tdClTot);

    trCl.addEventListener('click', () => {
      const isOpen = trCl.dataset.open === '1';
      trCl.dataset.open = isOpen ? '0' : '1';
      const tog = document.getElementById(clId+'-tog');
      if (tog) tog.textContent = isOpen ? '+' : '−';
      tbody.querySelectorAll(`[data-parent="${clId}"]`).forEach(r => { r.style.display = isOpen ? 'none' : ''; });
    });
    tbody.appendChild(trCl);

    // ── Client rows ───────────────────────────────────────────
    nds.forEach(nd => {
      let ndTot = 0;
      const trNd = document.createElement('tr');
      trNd.dataset.parent = clId;

      const tdN1 = document.createElement('td');
      tdN1.style.cssText = `${sCL}background:#161b22;border-bottom:1px solid #1c2128;border-right:1px solid #4a0a16;`;
      trNd.appendChild(tdN1);

      const tdN2 = document.createElement('td');
      tdN2.style.cssText = `${sND}background:#161b22;color:#c9d1d9;font-size:11px;padding:5px 10px;border-bottom:1px solid #1c2128;border-right:1px solid #30363d;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;`;
      tdN2.textContent = nd;
      trNd.appendChild(tdN2);

      meses.forEach(m => {
        const val = tree[cl][nd][m] || 0;
        ndTot += val;
        const td = document.createElement('td');
        td.style.cssText = 'text-align:right;padding:5px 10px;font-size:11px;border-bottom:1px solid #1c2128;white-space:nowrap;font-variant-numeric:tabular-nums;';
        if (val > 0) {
          const alpha = 0.07 + (val/maxVal)*0.52;
          td.style.background = `rgba(200,16,46,${alpha.toFixed(2)})`;
          td.style.color = alpha > 0.42 ? '#fff' : '#e6edf3';
          td.textContent = fmtNum(val,1);
        } else {
          td.style.color = '#30363d'; td.textContent = '—';
        }
        trNd.appendChild(td);
      });

      const tdNTot = document.createElement('td');
      tdNTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:5px 12px;font-size:11px;font-weight:600;color:#c9d1d9;background:#161b22;border-bottom:1px solid #1c2128;border-left:2px solid #4a0a16;white-space:nowrap;font-variant-numeric:tabular-nums;';
      tdNTot.textContent = ndTot > 0 ? fmtNum(ndTot,1) : '—';
      trNd.appendChild(tdNTot);
      tbody.appendChild(trNd);
    });

    // ── Subtotal row ──────────────────────────────────────────
    const trSub = document.createElement('tr');
    trSub.dataset.parent = clId;

    const tdS1 = document.createElement('td');
    tdS1.style.cssText = `${sCL}background:#2d0810;border-bottom:2px solid #4a0a16;border-right:1px solid #4a0a16;`;
    trSub.appendChild(tdS1);

    const tdS2 = document.createElement('td');
    tdS2.style.cssText = `${sND}background:#2d0810;color:#e8d5a3;font-size:11px;font-weight:700;padding:6px 10px;border-bottom:2px solid #4a0a16;border-right:1px solid #4a0a16;letter-spacing:.3px;`;
    tdS2.textContent = 'Subtotal';
    trSub.appendChild(tdS2);

    meses.forEach(m => {
      const val = clTotMes[m]||0;
      const td = document.createElement('td');
      td.style.cssText = 'text-align:right;padding:6px 10px;font-size:11px;font-weight:700;color:#e6edf3;background:#2d0810;border-bottom:2px solid #4a0a16;white-space:nowrap;font-variant-numeric:tabular-nums;';
      td.textContent = val > 0 ? fmtNum(val,1) : '—';
      trSub.appendChild(td);
    });

    const tdSTot = document.createElement('td');
    tdSTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:6px 12px;font-size:11px;font-weight:800;color:#e8d5a3;background:#2d0810;border-bottom:2px solid #4a0a16;border-left:2px solid #4a0a16;white-space:nowrap;font-variant-numeric:tabular-nums;';
    tdSTot.textContent = fmtNum(clTotAll,1);
    trSub.appendChild(tdSTot);
    tbody.appendChild(trSub);
  });

  // ── Grand total ───────────────────────────────────────────────
  const trG = document.createElement('tr');
  const tdG1 = document.createElement('td');
  tdG1.style.cssText = `${sCL}background:#1a0408;color:#e8d5a3;font-size:11px;font-weight:900;padding:9px 10px;border-top:2px solid #c8102e;border-right:1px solid #4a0a16;text-transform:uppercase;letter-spacing:.5px;`;
  tdG1.textContent = 'Total';
  trG.appendChild(tdG1);

  const tdG2 = document.createElement('td');
  tdG2.style.cssText = `${sND}background:#1a0408;border-top:2px solid #c8102e;border-right:1px solid #4a0a16;`;
  trG.appendChild(tdG2);

  meses.forEach(m => {
    const val = colTot[m]||0;
    const td = document.createElement('td');
    td.style.cssText = 'text-align:right;padding:9px 10px;font-size:11px;font-weight:800;color:#e8d5a3;background:#1a0408;border-top:2px solid #c8102e;white-space:nowrap;font-variant-numeric:tabular-nums;';
    td.textContent = val > 0 ? fmtNum(val,1) : '—';
    trG.appendChild(td);
  });

  const tdGT = document.createElement('td');
  tdGT.style.cssText = 'position:sticky;right:0;text-align:right;padding:9px 12px;font-size:12px;font-weight:900;color:#e8d5a3;background:#1a0408;border-top:2px solid #c8102e;border-left:2px solid #4a0a16;white-space:nowrap;font-variant-numeric:tabular-nums;';
  tdGT.textContent = fmtNum(grandTotal,1);
  trG.appendChild(tdGT);
  tbody.appendChild(trG);
  tbl.appendChild(tbody);

  // Botón expandir/colapsar todo
  const expBtn = document.getElementById('fer-exp-all');
  if (expBtn) {
    expBtn.addEventListener('click', e => {
      e.stopPropagation();
      const clRows = [...tbody.querySelectorAll('tr[data-cl-id]')];
      const allOpen = clRows.every(r => r.dataset.open === '1');
      const next = allOpen ? '0' : '1';
      clRows.forEach(trCl => {
        trCl.dataset.open = next;
        const tog = trCl.querySelector('span[id$="-tog"]');
        if (tog) tog.textContent = next === '1' ? '−' : '+';
        const cid = trCl.dataset.clId;
        tbody.querySelectorAll(`[data-parent="${cid}"]`).forEach(r => { r.style.display = next==='1' ? '' : 'none'; });
      });
      expBtn.textContent = next === '1' ? '−' : '+';
    });
  }
}

// ── Feriado · Litros por Semana (pivot colapsable) ────────────
function renderFeriadoSemanas(rows) {
  const tbl = document.getElementById('feriado-semanas-tbl');
  if (!tbl) return;
  tbl.innerHTML = '';

  const fRows = rows.filter(r => FER_KEYS.includes(r.fa));
  if (!fRows.length) {
    tbl.innerHTML = '<tr><td style="color:#8b949e;padding:20px" colspan="20">Sin datos para el período seleccionado.</td></tr>';
    return;
  }

  // Semanas ISO únicas ordenadas desc
  const semanas = [...new Set(fRows.map(r => isoWeekKey(r.f)))].sort().reverse();

  // tree: cl → nd → semana → sum(li)
  const tree = {};
  fRows.forEach(r => {
    const wk = isoWeekKey(r.f);
    if (!tree[r.cl]) tree[r.cl] = {};
    if (!tree[r.cl][r.nd]) tree[r.cl][r.nd] = {};
    tree[r.cl][r.nd][wk] = (tree[r.cl][r.nd][wk] || 0) + r.li;
  });

  // Totales globales por semana
  const colTot = {};
  let grandTotal = 0;
  semanas.forEach(wk => {
    colTot[wk] = fRows.filter(r => isoWeekKey(r.f) === wk).reduce((s,r) => s + r.li, 0);
    grandTotal += colTot[wk];
  });
  const maxVal = Math.max(1, ...Object.values(colTot));

  // Año-grupos
  const yearGroups = [];
  semanas.forEach(wk => {
    const y = wk.slice(0,4);
    if (yearGroups.length && yearGroups[yearGroups.length-1].year === y)
      yearGroups[yearGroups.length-1].count++;
    else yearGroups.push({year:y, count:1});
  });

  const CL_W = '150px', ND_W = '185px';
  const sCL = `position:sticky;left:0;width:${CL_W};min-width:${CL_W};z-index:2;`;
  const sND = `position:sticky;left:${CL_W};width:${ND_W};min-width:${ND_W};z-index:2;`;

  // ── THEAD ─────────────────────────────────────────────────────
  const thead = document.createElement('thead');
  const tr1 = document.createElement('tr');

  const thCl = document.createElement('th');
  thCl.rowSpan = 2;
  thCl.style.cssText = `${sCL}position:sticky;top:0;background:#1a0408;z-index:7;color:#e8d5a3;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;padding:7px 10px;border-bottom:2px solid #4a0a16;text-align:left;border-right:1px solid #4a0a16;`;
  thCl.innerHTML = `<span id="fer-sem-exp-all" style="display:inline-flex;align-items:center;justify-content:center;width:15px;height:15px;border:1px solid #4a0a16;border-radius:2px;margin-right:7px;font-size:11px;font-weight:900;color:#e8d5a3;background:#2d0810;vertical-align:middle;cursor:pointer;flex-shrink:0" title="Expandir/colapsar todo">+</span>Clusterización`;
  tr1.appendChild(thCl);

  const thNd = document.createElement('th');
  thNd.rowSpan = 2;
  thNd.style.cssText = `${sND}position:sticky;top:0;background:#1a0408;z-index:7;color:#e8d5a3;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;padding:7px 10px;border-bottom:2px solid #4a0a16;text-align:left;border-right:1px solid #4a0a16;`;
  thNd.textContent = 'NombreDeFantasía';
  tr1.appendChild(thNd);

  yearGroups.forEach(g => {
    const th = document.createElement('th');
    th.colSpan = g.count;
    th.style.cssText = 'position:sticky;top:0;background:#2d0810;z-index:4;text-align:center;color:#e8d5a3;font-size:11px;font-weight:700;letter-spacing:1px;padding:5px 8px;border-bottom:1px solid #4a0a16;';
    th.textContent = g.year;
    tr1.appendChild(th);
  });

  const thTot = document.createElement('th');
  thTot.rowSpan = 2;
  thTot.style.cssText = 'position:sticky;top:0;right:0;background:#2d0810;z-index:6;text-align:right;color:#e8d5a3;font-size:10px;font-weight:700;padding:7px 12px;border-bottom:2px solid #4a0a16;border-left:2px solid #4a0a16;white-space:nowrap;';
  thTot.textContent = 'Total';
  tr1.appendChild(thTot);
  thead.appendChild(tr1);

  const tr2 = document.createElement('tr');
  semanas.forEach(wk => {
    const th = document.createElement('th');
    th.style.cssText = 'position:sticky;top:29px;background:#1a0408;z-index:4;color:#e8a0ac;font-size:11px;padding:4px 10px;text-align:right;white-space:nowrap;border-bottom:2px solid #4a0a16;';
    th.textContent = parseInt(wk.slice(6), 10);
    tr2.appendChild(th);
  });
  thead.appendChild(tr2);
  tbl.appendChild(thead);

  // ── TBODY ─────────────────────────────────────────────────────
  const tbody = document.createElement('tbody');
  const sortedCl = Object.keys(tree).sort((a,b) => {
    const s = k => semanas.reduce((t,wk) => t + Object.values(tree[k]).reduce((tt,nd) => tt+(nd[wk]||0),0),0);
    return s(b)-s(a);
  });

  sortedCl.forEach(cl => {
    const nds = Object.keys(tree[cl]).sort((a,b) => {
      const totA = semanas.reduce((s,wk) => s+(tree[cl][a][wk]||0),0);
      const totB = semanas.reduce((s,wk) => s+(tree[cl][b][wk]||0),0);
      return totB-totA;
    });
    const clId = 'fersem_'+cl.replace(/[^a-z0-9]/gi,'_');

    const clTotSem = {};
    let clTotAll = 0;
    semanas.forEach(wk => { clTotSem[wk] = nds.reduce((s,nd)=>s+(tree[cl][nd][wk]||0),0); clTotAll+=clTotSem[wk]; });

    // Cluster row (collapsed by default — starts with '0')
    const trCl = document.createElement('tr');
    trCl.dataset.open = '0';
    trCl.dataset.clId = clId;
    trCl.style.cursor = 'pointer';

    const tdCl1 = document.createElement('td');
    tdCl1.style.cssText = `${sCL}background:#1a0408;color:#e8d5a3;font-size:11px;font-weight:700;padding:7px 10px;border-bottom:1px solid #4a0a16;border-right:1px solid #4a0a16;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;`;
    tdCl1.innerHTML = `<span id="${clId}-tog" style="display:inline-flex;align-items:center;justify-content:center;width:14px;height:14px;border:1px solid #4a0a16;border-radius:2px;margin-right:7px;font-size:10px;font-weight:900;color:#e8d5a3;background:#2d0810;vertical-align:middle;flex-shrink:0">+</span>${cl}`;
    trCl.appendChild(tdCl1);

    const tdCl2 = document.createElement('td');
    tdCl2.style.cssText = `${sND}background:#1a0408;border-bottom:1px solid #4a0a16;border-right:1px solid #4a0a16;`;
    trCl.appendChild(tdCl2);

    semanas.forEach(wk => {
      const val = clTotSem[wk] || 0;
      const td = document.createElement('td');
      td.style.cssText = 'text-align:right;padding:7px 10px;font-size:11px;font-weight:700;background:#1a0408;border-bottom:1px solid #4a0a16;white-space:nowrap;font-variant-numeric:tabular-nums;';
      if (val > 0) {
        const alpha = 0.07 + (val/maxVal)*0.52;
        td.style.background = `rgba(200,16,46,${alpha.toFixed(2)})`;
        td.style.color = alpha > 0.42 ? '#fff' : '#e6edf3';
        td.textContent = fmtNum(val,1);
      } else {
        td.style.color = '#484f58'; td.textContent = '—';
      }
      trCl.appendChild(td);
    });

    const tdClTot = document.createElement('td');
    tdClTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:7px 12px;font-size:11px;font-weight:800;color:#e8d5a3;background:#1a0408;border-bottom:1px solid #4a0a16;border-left:2px solid #4a0a16;white-space:nowrap;font-variant-numeric:tabular-nums;';
    tdClTot.textContent = fmtNum(clTotAll,1);
    trCl.appendChild(tdClTot);

    trCl.addEventListener('click', () => {
      const isOpen = trCl.dataset.open === '1';
      trCl.dataset.open = isOpen ? '0' : '1';
      const tog = document.getElementById(clId+'-tog');
      if (tog) tog.textContent = isOpen ? '+' : '−';
      tbody.querySelectorAll(`[data-parent="${clId}"]`).forEach(r => { r.style.display = isOpen ? 'none' : ''; });
    });
    tbody.appendChild(trCl);

    // Client rows (hidden by default)
    nds.forEach(nd => {
      let ndTot = 0;
      const trNd = document.createElement('tr');
      trNd.dataset.parent = clId;
      trNd.style.display = 'none';

      const tdN1 = document.createElement('td');
      tdN1.style.cssText = `${sCL}background:#161b22;border-bottom:1px solid #1c2128;border-right:1px solid #4a0a16;`;
      trNd.appendChild(tdN1);

      const tdN2 = document.createElement('td');
      tdN2.style.cssText = `${sND}background:#161b22;color:#c9d1d9;font-size:11px;padding:5px 10px;border-bottom:1px solid #1c2128;border-right:1px solid #30363d;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;`;
      tdN2.textContent = nd;
      trNd.appendChild(tdN2);

      semanas.forEach(wk => {
        const val = tree[cl][nd][wk] || 0;
        ndTot += val;
        const td = document.createElement('td');
        td.style.cssText = 'text-align:right;padding:5px 10px;font-size:11px;border-bottom:1px solid #1c2128;white-space:nowrap;font-variant-numeric:tabular-nums;';
        if (val > 0) {
          const alpha = 0.07 + (val/maxVal)*0.52;
          td.style.background = `rgba(200,16,46,${alpha.toFixed(2)})`;
          td.style.color = alpha > 0.42 ? '#fff' : '#e6edf3';
          td.textContent = fmtNum(val,1);
        } else {
          td.style.color = '#30363d'; td.textContent = '—';
        }
        trNd.appendChild(td);
      });

      const tdNTot = document.createElement('td');
      tdNTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:5px 12px;font-size:11px;font-weight:600;color:#c9d1d9;background:#161b22;border-bottom:1px solid #1c2128;border-left:2px solid #4a0a16;white-space:nowrap;font-variant-numeric:tabular-nums;';
      tdNTot.textContent = ndTot > 0 ? fmtNum(ndTot,1) : '—';
      trNd.appendChild(tdNTot);
      tbody.appendChild(trNd);
    });

    // Subtotal row (hidden by default)
    const trSub = document.createElement('tr');
    trSub.dataset.parent = clId;
    trSub.style.display = 'none';

    const tdS1 = document.createElement('td');
    tdS1.style.cssText = `${sCL}background:#2d0810;border-bottom:2px solid #4a0a16;border-right:1px solid #4a0a16;`;
    trSub.appendChild(tdS1);

    const tdS2 = document.createElement('td');
    tdS2.style.cssText = `${sND}background:#2d0810;color:#e8d5a3;font-size:11px;font-weight:700;padding:6px 10px;border-bottom:2px solid #4a0a16;border-right:1px solid #4a0a16;letter-spacing:.3px;`;
    tdS2.textContent = 'Subtotal';
    trSub.appendChild(tdS2);

    semanas.forEach(wk => {
      const val = clTotSem[wk]||0;
      const td = document.createElement('td');
      td.style.cssText = 'text-align:right;padding:6px 10px;font-size:11px;font-weight:700;color:#e6edf3;background:#2d0810;border-bottom:2px solid #4a0a16;white-space:nowrap;font-variant-numeric:tabular-nums;';
      td.textContent = val > 0 ? fmtNum(val,1) : '—';
      trSub.appendChild(td);
    });

    const tdSTot = document.createElement('td');
    tdSTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:6px 12px;font-size:11px;font-weight:800;color:#e8d5a3;background:#2d0810;border-bottom:2px solid #4a0a16;border-left:2px solid #4a0a16;white-space:nowrap;font-variant-numeric:tabular-nums;';
    tdSTot.textContent = fmtNum(clTotAll,1);
    trSub.appendChild(tdSTot);
    tbody.appendChild(trSub);
  });

  // Grand total
  const trG = document.createElement('tr');
  const tdG1 = document.createElement('td');
  tdG1.style.cssText = `${sCL}background:#1a0408;color:#e8d5a3;font-size:11px;font-weight:900;padding:9px 10px;border-top:2px solid #c8102e;border-right:1px solid #4a0a16;text-transform:uppercase;letter-spacing:.5px;`;
  tdG1.textContent = 'Total';
  trG.appendChild(tdG1);
  const tdG2 = document.createElement('td');
  tdG2.style.cssText = `${sND}background:#1a0408;border-top:2px solid #c8102e;border-right:1px solid #4a0a16;`;
  trG.appendChild(tdG2);
  semanas.forEach(wk => {
    const val = colTot[wk]||0;
    const td = document.createElement('td');
    td.style.cssText = 'text-align:right;padding:9px 10px;font-size:11px;font-weight:800;color:#e8d5a3;background:#1a0408;border-top:2px solid #c8102e;white-space:nowrap;font-variant-numeric:tabular-nums;';
    td.textContent = val > 0 ? fmtNum(val,1) : '—';
    trG.appendChild(td);
  });
  const tdGT = document.createElement('td');
  tdGT.style.cssText = 'position:sticky;right:0;text-align:right;padding:9px 12px;font-size:12px;font-weight:900;color:#e8d5a3;background:#1a0408;border-top:2px solid #c8102e;border-left:2px solid #4a0a16;white-space:nowrap;font-variant-numeric:tabular-nums;';
  tdGT.textContent = fmtNum(grandTotal,1);
  trG.appendChild(tdGT);
  tbody.appendChild(trG);
  tbl.appendChild(tbody);

  // Botón expandir/colapsar todo
  const expBtn = document.getElementById('fer-sem-exp-all');
  if (expBtn) {
    expBtn.addEventListener('click', e => {
      e.stopPropagation();
      const clRows = [...tbody.querySelectorAll('tr[data-cl-id]')];
      const allOpen = clRows.every(r => r.dataset.open === '1');
      const next = allOpen ? '0' : '1';
      clRows.forEach(trCl => {
        trCl.dataset.open = next;
        const tog = trCl.querySelector('span[id$="-tog"]');
        if (tog) tog.textContent = next === '1' ? '−' : '+';
        const cid = trCl.dataset.clId;
        tbody.querySelectorAll(`[data-parent="${cid}"]`).forEach(r => { r.style.display = next==='1' ? '' : 'none'; });
      });
      expBtn.textContent = next === '1' ? '−' : '+';
    });
  }
}

function renderFeriadoTab(rows, rowsYoY, rowsPop) {
  const pop      = getPrevPeriodRange();
  const fRows    = rows.filter(r => FER_KEYS.includes(r.fa));
  const fRowsYoY = rowsYoY.filter(r => FER_KEYS.includes(r.fa));
  const fRowsPop = (rowsPop || []).filter(r => FER_KEYS.includes(r.fa));

  const totalLit    = fRows.reduce((s,r) => s + r.li, 0);
  const totalLitYoY = fRowsYoY.reduce((s,r) => s + r.li, 0);
  const totalFac    = fRows.reduce((s,r) => s + r.to, 0);
  const totalFacPop = fRowsPop.reduce((s,r) => s + r.to, 0);

  // ── Gauge (litros) ────────────────────────────────────────────
  const GAUGE_MAX = Math.max(Math.ceil(totalLit * 1.6 / 100) * 100, 200);
  const p = Math.min(totalLit / GAUGE_MAX, 1);
  const angle = -Math.PI + Math.PI * p;
  const ex = 100 + 80 * Math.cos(angle);
  const ey = 100 + 80 * Math.sin(angle);
  const arcPath = p < 0.001
    ? 'M 20 100'
    : `M 20 100 A 80 80 0 ${p >= 0.9999 ? 1 : 0} 1 ${ex.toFixed(2)} ${ey.toFixed(2)}`;
  const arcEl = document.getElementById('fer-gauge-arc');
  if (arcEl) arcEl.setAttribute('d', arcPath);
  const valEl = document.getElementById('fer-gauge-val');
  if (valEl) valEl.textContent = fmtNum(totalLit, 1);
  const maxEl = document.getElementById('fer-gauge-max-lbl');
  if (maxEl) maxEl.textContent = GAUGE_MAX >= 1000
    ? (GAUGE_MAX/1000).toFixed(GAUGE_MAX%1000===0?0:1)+' mil' : GAUGE_MAX;
  const totalLitPop = fRowsPop.reduce((s,r) => s + r.li, 0);
  const badgeEl = document.getElementById('fer-gauge-badge');
  if (badgeEl) {
    let html = '';
    if (totalLitYoY > 0) {
      const pct = (totalLit - totalLitYoY) / totalLitYoY * 100;
      const col = pct >= 0 ? '#6ee7b7' : '#fca5a5';
      html += `<span style="color:${col};font-size:13px;font-weight:700">${pct>=0?'+':''}${pct.toFixed(1)}%</span>`
            + `<span style="color:#6e7681;font-size:10px;margin-left:4px">aa</span>`;
    } else {
      html += '<span style="color:#6e7681;font-size:10px">— aa</span>';
    }
    if (totalLitPop > 0) {
      const pct2 = (totalLit - totalLitPop) / totalLitPop * 100;
      const col2 = pct2 >= 0 ? '#60a5fa' : '#fca5a5';
      html += `<br><span style="color:${col2};font-size:12px;font-weight:700">${pct2>=0?'+':''}${pct2.toFixed(1)}%</span>`
            + `<span style="color:#6e7681;font-size:10px;margin-left:4px">per. ant.</span>`;
    }
    badgeEl.innerHTML = html;
  }

  // ── KPIs de producto (litros) ─────────────────────────────────
  const faMap    = byKey(fRows,    'fa');
  const faMapYoY = byKey(fRowsYoY, 'fa');
  const faMapPop = byKey(fRowsPop, 'fa');
  FER_PRODUCTS.forEach(prod => {
    const li    = faMap[prod.fa]?.li    || 0;
    const liYoY = faMapYoY[prod.fa]?.li || 0;
    const liPop = faMapPop[prod.fa]?.li || 0;
    const vEl   = document.getElementById(prod.kpiId);
    const sEl   = document.getElementById(prod.subId);
    if (vEl) vEl.textContent = li > 0 ? fmtNum(li, 1) : '—';
    if (sEl) {
      let html = '';
      if (liYoY > 0 && li > 0) {
        const pct = (li - liYoY) / liYoY * 100;
        const col = pct >= 0 ? '#6ee7b7' : '#fca5a5';
        html += `<span style="color:${col};font-weight:700">${pct>=0?'+':''}${pct.toFixed(1)}%</span>`
              + `<span style="color:#6e7681;font-size:10px;margin-left:3px">aa</span>`;
      } else {
        html += '<span style="color:#6e7681;font-size:10px">— aa</span>';
      }
      if (liPop > 0 && li > 0) {
        const pct2 = (li - liPop) / liPop * 100;
        const col2 = pct2 >= 0 ? '#60a5fa' : '#fca5a5';
        html += `<span style="color:#6e7681;font-size:10px;margin:0 4px">·</span>`
              + `<span style="color:${col2};font-weight:700">${pct2>=0?'+':''}${pct2.toFixed(1)}%</span>`
              + `<span style="color:#6e7681;font-size:10px;margin-left:3px">per. ant.</span>`;
      }
      sEl.innerHTML = html || '<span style="color:#6e7681;font-size:10px">—</span>';
    }
  });

  // ── Facturación Bruta ─────────────────────────────────────────
  const facEl = document.getElementById('fer-fac-val');
  if (facEl) {
    const v = totalFac;
    facEl.textContent = v >= 1e6
      ? '$ ' + (v/1e6).toLocaleString('es-AR',{minimumFractionDigits:1,maximumFractionDigits:1}) + 'M'
      : '$ ' + Math.round(v).toLocaleString('es-AR');
  }
  const facSubEl = document.getElementById('fer-fac-sub');
  if (facSubEl) {
    if (totalFacPop > 0) {
      const pct = (totalFac - totalFacPop) / totalFacPop * 100;
      const col = pct >= 0 ? '#6ee7b7' : '#fca5a5';
      const arr = pct >= 0 ? '↑' : '↓';
      facSubEl.innerHTML = `<span style="color:${col};font-size:14px;font-weight:700">${pct>=0?'+':''}${pct.toFixed(1)}% ${arr}</span>`
        + `<span style="color:#6e7681;font-size:11px;margin-left:4px">vs per. ant.</span>`;
    } else {
      facSubEl.innerHTML = '<span style="color:#6e7681;font-size:11px">—</span>';
    }
  }

  // ── Tabla de canales (litros, comparación dinámica) ──────────
  const cmpLblEl = document.getElementById('fer-tbl-cmp-lbl');
  if (cmpLblEl) cmpLblEl.textContent = 'vs per. ant.';

  const clData    = byKey(fRows,    'cl');
  const clDataCmp = byKey(fRowsPop, 'cl');
  const sortedCl  = Object.entries(clData).sort((a,b) => b[1].li - a[1].li);
  const totLi     = sortedCl.reduce((s,[,v]) => s + v.li, 0);
  const maxLi     = sortedCl[0]?.[1].li || 1;

  const tbody = document.getElementById('fer-tbl-body');
  if (tbody) {
    tbody.innerHTML = '';
    sortedCl.forEach(([cl, v], i) => {
      const cmpLi = clDataCmp[cl]?.li || 0;
      const barW  = Math.max(2, Math.round(v.li / maxLi * 100));
      let pctHtml;
      if (cmpLi > 0) {
        const pp  = (v.li - cmpLi) / cmpLi * 100;
        const cls = pp >= 0 ? 'pct-up' : 'pct-dn';
        pctHtml = `<span class="pct-badge ${cls}">${pp>=0?'+':''}${pp.toFixed(1)}%</span>`;
      } else {
        pctHtml = `<span style="color:#484f58;font-size:11px">—</span>`;
      }
      const tr = document.createElement('tr');
      tr.innerHTML = `
        <td style="color:#484f58;font-size:11px;text-align:center;padding:8px 4px">${i+1}</td>
        <td style="color:#e6edf3;padding:8px 10px;font-size:12px">${cl}</td>
        <td class="r" style="padding:8px 12px;white-space:nowrap">
          <div style="display:flex;align-items:center;justify-content:flex-end;gap:8px">
            <div style="width:72px;height:5px;background:#21262d;border-radius:3px;flex-shrink:0">
              <div style="width:${barW}%;height:100%;background:#c8102e;border-radius:3px"></div>
            </div>
            <span style="font-variant-numeric:tabular-nums;font-size:13px;font-weight:600;min-width:48px;text-align:right">${fmtNum(v.li,1)}</span>
          </div>
        </td>
        <td class="r" style="padding:8px 12px">${pctHtml}</td>`;
      tbody.appendChild(tr);
    });

    // Fila total
    const trT = document.createElement('tr');
    trT.className = 'tr-total';
    const totCmpLi = Object.values(clDataCmp).reduce((s,v) => s + v.li, 0);
    let totPctHtml;
    if (totCmpLi > 0) {
      const pp  = (totLi - totCmpLi) / totCmpLi * 100;
      const cls = pp >= 0 ? 'pct-up' : 'pct-dn';
      totPctHtml = `<span class="pct-badge ${cls}">${pp>=0?'+':''}${pp.toFixed(1)}%</span>`;
    } else {
      totPctHtml = `<span style="color:#484f58;font-size:11px">—</span>`;
    }
    trT.innerHTML = `
      <td style="padding:9px 4px"></td>
      <td style="padding:9px 10px;color:#e8d5a3;font-weight:800;font-size:12px">Total</td>
      <td class="r" style="padding:9px 12px;font-variant-numeric:tabular-nums;font-size:13px;font-weight:800;color:#e8d5a3">${fmtNum(totLi,1)}</td>
      <td class="r" style="padding:9px 12px">${totPctHtml}</td>`;
    tbody.appendChild(trT);
  }

  // ── Donuts (litros) ───────────────────────────────────────────
  loadChartJS(function() {
    if (typeof Chart === 'undefined') return;

    // Mix Producto
    const prodLabels = [], prodData = [], prodColors = [];
    FER_PRODUCTS.forEach(p => {
      const li = faMap[p.fa]?.li || 0;
      if (li > 0) {
        prodLabels.push(p.label);
        prodData.push(Math.round(li * 10) / 10);
        prodColors.push(p.color);
      }
    });
    const canvP = document.getElementById('fer-chart-prod');
    if (canvP) {
      if (canvP._chart) canvP._chart.destroy();
      canvP._chart = new Chart(canvP, {
        type: 'doughnut',
        data: { labels: prodLabels, datasets: [{ data: prodData, backgroundColor: prodColors, borderWidth: 2, borderColor: '#0d1117' }] },
        options: {
          responsive: true, maintainAspectRatio: false, cutout: '62%',
          plugins: {
            legend: { position:'bottom', labels: { color:'#c9d1d9', font:{size:11}, padding:12, boxWidth:12 } },
            tooltip: { callbacks: { label: ctx => ` ${ctx.label}: ${ctx.parsed.toLocaleString('es-AR',{maximumFractionDigits:1})} L` } }
          }
        }
      });
    }

    // Mix Canal
    const canalEntries = Object.entries(clData).sort((a,b) => b[1].li - a[1].li);
    const TOP = 5;
    const canalLabels = [], canalData = [];
    const CANAL_COLORS = ['#c8102e','#e63950','#f07080','#f9a8b8','#fca5a5','#8b949e'];
    let otrosTotal = 0;
    canalEntries.forEach(([cl, v], i) => {
      if (i < TOP) { canalLabels.push(cl); canalData.push(Math.round(v.li * 10)/10); }
      else otrosTotal += v.li;
    });
    if (otrosTotal > 0) { canalLabels.push('Otros'); canalData.push(Math.round(otrosTotal*10)/10); }

    const canvC = document.getElementById('fer-chart-canal');
    if (canvC) {
      if (canvC._chart) canvC._chart.destroy();
      canvC._chart = new Chart(canvC, {
        type: 'doughnut',
        data: { labels: canalLabels, datasets: [{ data: canalData, backgroundColor: CANAL_COLORS.slice(0, canalData.length), borderWidth: 2, borderColor: '#0d1117' }] },
        options: {
          responsive: true, maintainAspectRatio: false, cutout: '62%',
          plugins: {
            legend: { position:'bottom', labels: { color:'#c9d1d9', font:{size:11}, padding:12, boxWidth:12 } },
            tooltip: { callbacks: { label: ctx => ` ${ctx.label}: ${ctx.parsed.toLocaleString('es-AR',{maximumFractionDigits:1})} L` } }
          }
        }
      });
    }
  });
  renderObjPanel('feriado', fRows, 'feriado-obj-panel');
}

// ============================================================
// OBJETIVOS
// ============================================================
const OBJ_MES = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
const OBJ_PROD_LABELS = {
  bosque_nativo:'Bosque Nativo', bosque_alta_montana:'Alta Montaña',
  bosque_refugios:'Refugios', bosque_nativo_mini:'Nativo Mini',
  bosque_alta_montana_mini:'AM Mini', bosque_otro:'Otros Gin',
  feriado_rojo:'Rojo 750ml', feriado_rosado:'Rosado 750ml',
  feriado_barril_20:'Barril 20lt', feriado_barril_50:'Barril 50lt',
  lata_wolf:'Wolf IPA', lata_scottish:'Scottish',
  lata_wolf0:'Wolf IPA 0%', lata_golden:'Indie Golden', lata_otras:'Otras Latas',
};
const BRAND_FA_KEYS = {
  bosque:  ['bosque_nativo','bosque_alta_montana','bosque_refugios','bosque_nativo_mini','bosque_alta_montana_mini','bosque_otro'],
  feriado: ['feriado_rojo','feriado_rosado','feriado_barril_20','feriado_barril_50'],
  cerveza: ['lata_wolf','lata_scottish','lata_golden','lata_wolf0','lata_otras']
};

function getObjMonths() {
  if (!S.desde || !S.hasta) return [];
  const d0 = new Date(S.desde + 'T00:00:00'), d1 = new Date(S.hasta + 'T00:00:00');
  const months = [];
  let cur = new Date(d0.getFullYear(), d0.getMonth(), 1);
  while (cur <= d1 && months.length < 12) {
    if (cur.getFullYear() === 2026) months.push(cur.getMonth());
    cur = new Date(cur.getFullYear(), cur.getMonth() + 1, 1);
  }
  return months;
}

function objSum(arr, months) {
  return (!arr || !months.length) ? 0 : months.reduce((s, m) => s + (arr[m] || 0), 0);
}

function objBarColor(pct) {
  if (pct === null) return '#6e7681';
  return pct >= 100 ? '#3fb950' : pct >= 85 ? '#d29922' : '#f85149';
}

function objPctHtml(real, target) {
  if (!target) return '<span class="pct-na">—</span>';
  const pct = real / target * 100;
  const c = objBarColor(pct);
  return `<span style="font-weight:700;color:${c}">${pct.toFixed(1)}%</span>`
       + `<div class="obj-bar"><div class="obj-bar-fill" style="width:${Math.min(pct,100).toFixed(1)}%;background:${c}"></div></div>`;
}

function renderObjPanel(brand, brandRows, panelId) {
  const el = document.getElementById(panelId);
  if (!el) return;
  const months = getObjMonths();
  const bObj   = OBJ && OBJ[brand];
  if (!months.length || !bObj) { el.style.display = 'none'; return; }
  el.style.display = 'block';

  const COLORS = { bosque:'#e8d5a3', feriado:'#c8102e', cerveza:'#38bdf8' };
  const color  = COLORS[brand] || '#e8d5a3';
  const mesLbl = months.length === 1
    ? OBJ_MES[months[0]] + ' 2026'
    : OBJ_MES[months[0]] + '–' + OBJ_MES[months[months.length-1]] + ' 2026';

  // Acumulados reales por producto y cluster
  const actProd = {}, actCl = {};
  let totalReal = 0;
  brandRows.forEach(r => {
    actProd[r.fa] = (actProd[r.fa] || 0) + r.li;
    actCl[r.cl]   = (actCl[r.cl]   || 0) + r.li;
    totalReal    += r.li;
  });
  // realByMonth usa ROWS global para cubrir todo el año independientemente del filtro activo
  const realByMonth = {};
  var _faKeys = BRAND_FA_KEYS[brand];
  (ROWS || []).forEach(function(r) {
    if (r.f && r.f.substring(0,4) === '2026' && (!_faKeys || _faKeys.includes(r.fa))) {
      var mm = parseInt(r.f.substring(5,7)) - 1;
      realByMonth[mm] = (realByMonth[mm] || 0) + r.li;
    }
  });

  const totalObj = objSum(bObj.cluster?._TOTAL || bObj.product?._TOTAL, months);
  const pctTot   = totalObj ? totalReal / totalObj * 100 : null;
  const cTot     = objBarColor(pctTot);
  const delta    = totalObj ? (totalReal - totalObj) : 0;

  let html = `<div class="obj-section" style="border-top-color:${color}">
  <div class="obj-sec-hdr">
    <div class="obj-sec-title">OBJETIVOS</div>
    <div class="obj-sec-mes" style="color:${color}">${mesLbl}</div>
  </div>
  <div class="obj-summary">
    <div><div class="obj-sum-lbl">OBJETIVO</div>
      <div class="obj-sum-val" style="color:${color}">${fmtNum(totalObj,0)}</div>
      <div class="obj-sum-sub">litros</div></div>
    <div><div class="obj-sum-lbl">REAL</div>
      <div class="obj-sum-val">${fmtNum(totalReal,1)}</div>
      <div class="obj-sum-sub">litros</div></div>
    <div><div class="obj-sum-lbl">CUMPL.</div>
      <div class="obj-sum-val" style="color:${cTot}">${pctTot !== null ? pctTot.toFixed(1)+'%' : '—'}</div>
      <div class="obj-sum-sub" style="color:${cTot}">${totalObj ? (delta>=0?'+':'')+fmtNum(delta,1)+' L' : ''}</div></div>
  </div>`;

  const prodRows = Object.entries(bObj.product || {})
    .filter(([k]) => k !== '_TOTAL')
    .map(([k,arr]) => [k, objSum(arr, months)])
    .filter(([,v]) => v > 0)
    .sort((a,b) => b[1]-a[1]);

  const clRows = Object.entries(bObj.cluster || {})
    .filter(([k]) => k !== '_TOTAL')
    .map(([k,arr]) => [k, objSum(arr, months)])
    .filter(([,v]) => v > 0)
    .sort((a,b) => b[1]-a[1]);

  function pctBadge(rv, ov) {
    if (!ov) return '<span style="color:#6e7681">—</span>';
    const pct = rv / ov * 100;
    const c = objBarColor(pct);
    const bg = c === '#3fb950' ? 'rgba(63,185,80,.12)' : c === '#d29922' ? 'rgba(210,153,34,.12)' : 'rgba(248,81,73,.12)';
    return '<span style="display:inline-block;padding:1px 7px;border-radius:20px;font-size:11px;font-weight:700;color:' + c + ';background:' + bg + ';border:1px solid ' + c + '33">' + pct.toFixed(1) + '%</span>';
  }

  function buildTbl(title, rows, actMap, nameFn) {
    if (!rows.length) return '';
    let t = '<div style="flex:1;min-width:0"><div class="obj-sub-hdr">' + title + '</div>'
      + '<table class="obj-tbl" style="table-layout:fixed;width:100%"><colgroup>'
      + '<col><col style="width:62px"><col style="width:68px"><col style="width:96px"></colgroup>'
      + '<thead><tr>'
      + '<th style="color:#6e7681">Nombre</th>'
      + '<th class="r" style="color:#6e7681">Obj</th>'
      + '<th class="r" style="color:#6e7681">Real</th>'
      + '<th class="r" style="color:#6e7681">%</th>'
      + '</tr></thead><tbody>';
    rows.forEach(function(row) {
      var k = row[0], ov = row[1];
      var rv = actMap[k] || 0;
      t += '<tr>'
        + '<td style="color:#c9d1d9;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + nameFn(k) + '</td>'
        + '<td class="r" style="color:#6e7681">' + fmtNum(ov,0) + '</td>'
        + '<td class="r" style="color:#e6edf3;font-weight:600">' + fmtNum(rv,1) + '</td>'
        + '<td class="r">' + pctBadge(rv,ov) + '</td>'
        + '</tr>';
    });
    t += '</tbody></table></div>';
    return t;
  }

  // --- Ritmo diario ---
  var today = new Date();
  var todayYear = today.getFullYear(), todayMonth = today.getMonth();
  var paceHtml = '', projClHtml = '';
  if (todayYear === 2026 && months.indexOf(todayMonth) !== -1) {
    var daysInMonth = new Date(2026, todayMonth + 1, 0).getDate();
    var daysElapsed = today.getDate();
    var paceRatio = daysElapsed / daysInMonth;
    var totalArr0 = (bObj.cluster && bObj.cluster._TOTAL) || (bObj.product && bObj.product._TOTAL);
    var monthObj0 = totalArr0 ? (totalArr0[todayMonth] || 0) : 0;
    var paceTarget = monthObj0 * paceRatio;
    var monthReal = realByMonth[todayMonth] || 0;
    var paceDelta = monthReal - paceTarget;
    var pacePct = paceTarget ? monthReal / paceTarget * 100 : null;
    var paceC = objBarColor(pacePct);
    paceHtml = '<div style="background:#0d1117;border-radius:10px;padding:12px 14px;margin-bottom:14px">'
      + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px">'
      + '<span style="font-size:10px;font-weight:700;letter-spacing:.5px;color:#6e7681;text-transform:uppercase">RITMO DIARIO</span>'
      + '<span style="font-size:11px;font-weight:600;color:' + color + '">' + OBJ_MES[todayMonth] + ' &middot; D&iacute;a ' + daysElapsed + ' de ' + daysInMonth + ' (' + (paceRatio*100).toFixed(0) + '% del mes)</span>'
      + '</div>'
      + '<div style="display:flex;gap:16px;align-items:center">'
      + '<div style="min-width:82px;text-align:center">'
      + '<div style="font-size:9px;color:#6e7681;text-transform:uppercase;letter-spacing:.4px;margin-bottom:3px">Esperado</div>'
      + '<div style="font-size:20px;font-weight:900;color:#6e7681;letter-spacing:-.5px">' + fmtNum(paceTarget,0) + '</div>'
      + '<div style="font-size:9px;color:#6e7681;margin-top:2px">litros</div></div>'
      + '<div style="flex:1">'
      + '<div style="height:5px;border-radius:3px;background:#21262d;overflow:hidden;margin-bottom:7px">'
      + '<div style="height:5px;border-radius:3px;background:' + paceC + ';width:' + Math.min(pacePct||0,100).toFixed(1) + '%"></div></div>'
      + '<div style="text-align:center;font-size:13px;font-weight:700;color:' + paceC + '">'
      + (paceDelta >= 0 ? '+' : '') + fmtNum(paceDelta,1) + ' L'
      + (pacePct !== null ? ' &nbsp;&middot;&nbsp; ' + pacePct.toFixed(1) + '% del ritmo' : '')
      + '</div></div>'
      + '<div style="min-width:82px;text-align:center">'
      + '<div style="font-size:9px;color:#6e7681;text-transform:uppercase;letter-spacing:.4px;margin-bottom:3px">Real</div>'
      + '<div style="font-size:20px;font-weight:900;color:#e6edf3;letter-spacing:-.5px">' + fmtNum(monthReal,1) + '</div>'
      + '<div style="font-size:9px;color:#6e7681;margin-top:2px">litros</div></div>'
      + '</div></div>';

  // --- Proyección al cierre por cluster ---
  var actClMes = {};
  var mesStr = '2026-' + String(todayMonth + 1).padStart(2, '0');
  (ROWS || []).forEach(function(r) {
    if (r.f && r.f.substring(0, 7) === mesStr && (!_faKeys || _faKeys.includes(r.fa))) {
      actClMes[r.cl] = (actClMes[r.cl] || 0) + r.li;
    }
  });
  var clObjMes = {};
  Object.entries(bObj.cluster || {}).forEach(function([k, arr]) {
    if (k !== '_TOTAL') clObjMes[k] = arr[todayMonth] || 0;
  });
  var projRows = Object.entries(actClMes)
    .map(function([k, rv]) {
      var proj = rv / paceRatio;
      var ov   = clObjMes[k] || 0;
      var pct  = ov ? proj / ov * 100 : null;
      var diff = rv - (ov * paceRatio);
      return { k: k, rv: rv, proj: proj, ov: ov, pct: pct, diff: diff };
    })
    .filter(function(r) { return r.rv > 0; })
    .sort(function(a, b) { return b.proj - a.proj; });
  if (projRows.length) {
    projClHtml = '<div style="margin-top:14px">'
      + '<div class="obj-sub-hdr">LITROS ESTIMADOS AL CIERRE — POR CLUSTER</div>'
      + '<table class="obj-tbl"><colgroup>'
      + '<col style="width:36%"><col style="width:14%"><col style="width:18%"><col style="width:13%"><col style="width:19%">'
      + '</colgroup><thead><tr>'
      + '<th style="color:#6e7681">Cluster</th>'
      + '<th class="r" style="color:#6e7681">Real</th>'
      + '<th class="r" style="color:#6e7681">Lts.&nbsp;est.</th>'
      + '<th class="r" style="color:#6e7681">Obj</th>'
      + '<th class="r" style="color:#6e7681">%&nbsp;est.</th>'
      + '</tr></thead><tbody>';
    projRows.forEach(function(r) {
      var c  = r.pct===null?'#6e7681':r.pct>=100?'#3fb950':r.pct>=85?'#d29922':'#f85149';
      var bg = r.pct===null?'transparent':r.pct>=100?'rgba(63,185,80,.12)':r.pct>=85?'rgba(210,153,34,.12)':'rgba(248,81,73,.12)';
      var badge = r.pct!==null
        ? '<span style="display:inline-block;padding:1px 6px;border-radius:20px;font-size:11px;font-weight:700;color:'+c+';background:'+bg+';border:1px solid '+c+'33">'+r.pct.toFixed(1)+'%</span>'
        : '<span style="color:#6e7681">—</span>';
      var diffSign = r.diff >= 0 ? '+' : '';
      var diffColor = r.diff >= 0 ? '#3fb950' : '#f85149';
      projClHtml += '<tr>'
        + '<td style="color:#c9d1d9;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+r.k+'</td>'
        + '<td class="r" style="white-space:nowrap"><span style="color:#e6edf3;font-weight:600">'+fmtNum(r.rv,0)+'</span>'
          + '&nbsp;<span style="font-size:9px;color:'+diffColor+'">'+diffSign+Math.round(r.diff)+'</span></td>'
        + '<td class="r" style="color:#e6edf3;font-weight:700">'+fmtNum(r.proj,0)+'</td>'
        + '<td class="r" style="color:#6e7681">'+(r.ov ? fmtNum(r.ov,0) : '—')+'</td>'
        + '<td class="r">'+badge+'</td>'
        + '</tr>';
    });
    projClHtml += '</tbody></table></div>';
  }
  }

  // --- Mes a mes ---
  var totalArr = (bObj.cluster && bObj.cluster._TOTAL) || (bObj.product && bObj.product._TOTAL);
  var mesAMesHtml = '';
  if (totalArr) {
    var mesRows = [];
    totalArr.forEach(function(ov, m) { if (ov > 0) mesRows.push({ m: m, ov: ov, rv: realByMonth[m] || 0 }); });
    if (mesRows.length > 1) {
      mesAMesHtml = '<div style="margin-top:16px"><div class="obj-sub-hdr">MES A MES 2026</div>'
        + '<table class="obj-tbl" style="table-layout:fixed;width:100%"><colgroup>'
        + '<col style="width:46px">'
        + '<col style="width:76px">'
        + '<col style="width:76px">'
        + '<col style="width:100px">'
        + '<col>'
        + '</colgroup>'
        + '<thead><tr>'
        + '<th style="color:#6e7681">Mes</th>'
        + '<th class="r" style="color:#6e7681">Obj</th>'
        + '<th class="r" style="color:#6e7681">Real</th>'
        + '<th class="r" style="color:#6e7681">%</th>'
        + '<th></th>'
        + '</tr></thead><tbody>';
      mesRows.forEach(function(row) {
        var isCurrent = (todayYear === 2026 && row.m === todayMonth);
        var isFuture  = (todayYear < 2026) || (todayYear === 2026 && row.m > todayMonth);
        var nStyle = isCurrent ? 'color:#e6edf3;font-weight:700' : isFuture ? 'color:#484f58' : 'color:#8b949e';
        var oStyle = isFuture ? 'color:#484f58' : 'color:#6e7681';
        var rStyle = isFuture ? 'color:#484f58' : 'color:#e6edf3;font-weight:600';
        var pct = (!isFuture && row.ov) ? row.rv / row.ov * 100 : 0;
        var barC = isFuture ? '#21262d' : objBarColor(row.ov ? pct : null);
        var barW = isFuture ? 0 : Math.min(pct, 100).toFixed(1);
        mesAMesHtml += '<tr'
          + (isCurrent ? ' style="background:rgba(255,255,255,.03)"' : '')
          + '>'
          + '<td style="' + nStyle + '">' + OBJ_MES[row.m] + '</td>'
          + '<td class="r" style="' + oStyle + '">' + fmtNum(row.ov,0) + '</td>'
          + '<td class="r" style="' + rStyle + '">' + (isFuture ? '<span style="color:#484f58">—</span>' : fmtNum(row.rv,1)) + '</td>'
          + '<td class="r">' + (isFuture ? '<span style="color:#484f58">—</span>' : pctBadge(row.rv, row.ov)) + '</td>'
          + '<td style="padding-left:8px;vertical-align:middle">'
          + '<div style="height:4px;border-radius:2px;background:#21262d;overflow:hidden">'
          + '<div style="height:4px;border-radius:2px;background:' + barC + ';width:' + barW + '%"></div>'
          + '</div></td>'
          + '</tr>';
      });
      mesAMesHtml += '</tbody></table></div>';
    }
  }

  var tablesHtml = buildTbl('POR PRODUCTO', prodRows, actProd, function(k){ return OBJ_PROD_LABELS[k]||k; })
    + buildTbl('POR CANAL / CLUSTER', clRows, actCl, function(k){ return k; });
  html += paceHtml;
  html += projClHtml;
  if (tablesHtml) {
    html += '<div style="display:flex;gap:16px;align-items:flex-start">' + tablesHtml + '</div>';
  }
  html += mesAMesHtml;
  html += '</div>';
  el.innerHTML = html;
}

// ============================================================
// BOSQUE
// ============================================================
const BOS_KEYS = ['bosque_nativo','bosque_alta_montana','bosque_refugios',
                  'bosque_nativo_mini','bosque_alta_montana_mini','bosque_otro'];

const BOS_PRODUCTS = [
  { fa:'bosque_nativo',            label:'Bosque Nativo',       color:'#e8d5a3', bg:'#2a1f08' },
  { fa:'bosque_alta_montana',      label:'Alta Montaña',        color:'#d4b880', bg:'#321e06' },
  { fa:'bosque_refugios',          label:'Refugios',            color:'#c9a96e', bg:'#281806' },
  { fa:'bosque_nativo_mini',       label:'Nativo Miniatura',    color:'#b89456', bg:'#1e1508' },
  { fa:'bosque_alta_montana_mini', label:'Alta Montaña Mini',   color:'#a07c3a', bg:'#1a1206' },
  { fa:'bosque_otro',              label:'Otros Gin',           color:'#8b949e', bg:'#1c2128' },
];

const BOS_GENERAL_PRODUCTS = [
  { fa:'bosque_nativo',       label:'Bosque Nativo', color:'#e8d5a3', kpiId:'bos-kpi-nativo',      subId:'bos-kpi-nativo-sub' },
  { fa:'bosque_alta_montana', label:'Alta Montaña',  color:'#d4b880', kpiId:'bos-kpi-altamontana', subId:'bos-kpi-altamontana-sub' },
  { fa:'bosque_refugios',     label:'Refugios',      color:'#c9a96e', kpiId:'bos-kpi-refugios',    subId:'bos-kpi-refugios-sub' },
  { fa:'bosque_otro',         label:'Otros Gin',     color:'#8b949e', kpiId:'bos-kpi-otro',        subId:'bos-kpi-otro-sub' },
];

function renderBosqueTab(rows, rowsYoY, rowsPop) {
  const bRows    = rows.filter(r => BOS_KEYS.includes(r.fa));
  const bRowsYoY = rowsYoY.filter(r => BOS_KEYS.includes(r.fa));
  const bRowsPop = (rowsPop || []).filter(r => BOS_KEYS.includes(r.fa));

  const totalLit    = bRows.reduce((s,r) => s + r.li, 0);
  const totalLitYoY = bRowsYoY.reduce((s,r) => s + r.li, 0);
  const totalLitPop = bRowsPop.reduce((s,r) => s + r.li, 0);
  const totalFac    = bRows.reduce((s,r) => s + r.to, 0);
  const totalFacPop = bRowsPop.reduce((s,r) => s + r.to, 0);

  // ── Gauge (litros) ────────────────────────────────────────────
  const GAUGE_MAX = Math.max(Math.ceil(totalLit * 1.6 / 100) * 100, 200);
  const p = Math.min(totalLit / GAUGE_MAX, 1);
  const angle = -Math.PI + Math.PI * p;
  const ex = 100 + 80 * Math.cos(angle);
  const ey = 100 + 80 * Math.sin(angle);
  const arcPath = p < 0.001
    ? 'M 20 100'
    : `M 20 100 A 80 80 0 ${p >= 0.9999 ? 1 : 0} 1 ${ex.toFixed(2)} ${ey.toFixed(2)}`;
  const arcEl = document.getElementById('bos-gauge-arc');
  if (arcEl) arcEl.setAttribute('d', arcPath);
  const valEl = document.getElementById('bos-gauge-val');
  if (valEl) valEl.textContent = fmtNum(totalLit, 1);
  const maxEl = document.getElementById('bos-gauge-max-lbl');
  if (maxEl) maxEl.textContent = GAUGE_MAX >= 1000
    ? (GAUGE_MAX/1000).toFixed(GAUGE_MAX%1000===0?0:1)+' mil' : GAUGE_MAX;
  const badgeEl = document.getElementById('bos-gauge-badge');
  if (badgeEl) {
    let html = '';
    if (totalLitYoY > 0) {
      const pct = (totalLit - totalLitYoY) / totalLitYoY * 100;
      const col = pct >= 0 ? '#6ee7b7' : '#fca5a5';
      html += `<span style="color:${col};font-size:13px;font-weight:700">${pct>=0?'+':''}${pct.toFixed(1)}%</span>`
            + `<span style="color:#6e7681;font-size:10px;margin-left:4px">aa</span>`;
    } else {
      html += '<span style="color:#6e7681;font-size:10px">— aa</span>';
    }
    if (totalLitPop > 0) {
      const pct2 = (totalLit - totalLitPop) / totalLitPop * 100;
      const col2 = pct2 >= 0 ? '#60a5fa' : '#fca5a5';
      html += `<br><span style="color:${col2};font-size:12px;font-weight:700">${pct2>=0?'+':''}${pct2.toFixed(1)}%</span>`
            + `<span style="color:#6e7681;font-size:10px;margin-left:4px">per. ant.</span>`;
    }
    badgeEl.innerHTML = html;
  }

  // ── KPIs de producto (litros) ─────────────────────────────────
  const faMap    = byKey(bRows,    'fa');
  const faMapYoY = byKey(bRowsYoY, 'fa');
  const faMapPop = byKey(bRowsPop, 'fa');
  BOS_GENERAL_PRODUCTS.forEach(prod => {
    const li    = faMap[prod.fa]?.li    || 0;
    const liYoY = faMapYoY[prod.fa]?.li || 0;
    const liPop = faMapPop[prod.fa]?.li || 0;
    const vEl   = document.getElementById(prod.kpiId);
    const sEl   = document.getElementById(prod.subId);
    if (vEl) vEl.textContent = li > 0 ? fmtNum(li, 1) : '—';
    if (sEl) {
      let html = '';
      if (liYoY > 0 && li > 0) {
        const pct = (li - liYoY) / liYoY * 100;
        const col = pct >= 0 ? '#6ee7b7' : '#fca5a5';
        html += `<span style="color:${col};font-weight:700">${pct>=0?'+':''}${pct.toFixed(1)}%</span>`
              + `<span style="color:#6e7681;font-size:10px;margin-left:3px">aa</span>`;
      } else {
        html += '<span style="color:#6e7681;font-size:10px">— aa</span>';
      }
      if (liPop > 0 && li > 0) {
        const pct2 = (li - liPop) / liPop * 100;
        const col2 = pct2 >= 0 ? '#60a5fa' : '#fca5a5';
        html += `<span style="color:#6e7681;font-size:10px;margin:0 4px">·</span>`
              + `<span style="color:${col2};font-weight:700">${pct2>=0?'+':''}${pct2.toFixed(1)}%</span>`
              + `<span style="color:#6e7681;font-size:10px;margin-left:3px">per. ant.</span>`;
      }
      sEl.innerHTML = html || '<span style="color:#6e7681;font-size:10px">—</span>';
    }
  });

  // ── Facturación Bruta ─────────────────────────────────────────
  const facEl = document.getElementById('bos-fac-val');
  if (facEl) {
    const v = totalFac;
    facEl.textContent = v >= 1e6
      ? '$ ' + (v/1e6).toLocaleString('es-AR',{minimumFractionDigits:1,maximumFractionDigits:1}) + 'M'
      : '$ ' + Math.round(v).toLocaleString('es-AR');
  }
  const facSubEl = document.getElementById('bos-fac-sub');
  if (facSubEl) {
    if (totalFacPop > 0) {
      const pct = (totalFac - totalFacPop) / totalFacPop * 100;
      const col = pct >= 0 ? '#6ee7b7' : '#fca5a5';
      const arr = pct >= 0 ? '↑' : '↓';
      facSubEl.innerHTML = `<span style="color:${col};font-size:14px;font-weight:700">${pct>=0?'+':''}${pct.toFixed(1)}% ${arr}</span>`
        + `<span style="color:#6e7681;font-size:11px;margin-left:4px">vs per. ant.</span>`;
    } else {
      facSubEl.innerHTML = '<span style="color:#6e7681;font-size:11px">—</span>';
    }
  }

  // ── Tabla de clusterización ────────────────────────────────────
  const cmpLblEl = document.getElementById('bos-cl-tbl-cmp-lbl');
  if (cmpLblEl) cmpLblEl.textContent = 'vs per. ant.';

  const clData    = byKey(bRows,    'cl');
  const clDataCmp = byKey(bRowsPop, 'cl');
  const sortedCl  = Object.entries(clData).sort((a,b) => b[1].li - a[1].li);
  const totLi     = sortedCl.reduce((s,[,v]) => s + v.li, 0);
  const maxLi     = sortedCl[0]?.[1].li || 1;

  const tbody = document.getElementById('bos-cl-tbl-body');
  if (tbody) {
    tbody.innerHTML = '';
    sortedCl.forEach(([cl, v], i) => {
      const cmpLi = clDataCmp[cl]?.li || 0;
      const barW  = Math.max(2, Math.round(v.li / maxLi * 100));
      let pctHtml;
      if (cmpLi > 0) {
        const pp  = (v.li - cmpLi) / cmpLi * 100;
        const cls = pp >= 0 ? 'pct-up' : 'pct-dn';
        pctHtml = `<span class="pct-badge ${cls}">${pp>=0?'+':''}${pp.toFixed(1)}%</span>`;
      } else {
        pctHtml = `<span style="color:#484f58;font-size:11px">—</span>`;
      }
      const tr = document.createElement('tr');
      tr.innerHTML = `
        <td style="color:#484f58;font-size:11px;text-align:center;padding:8px 4px">${i+1}</td>
        <td style="color:#e6edf3;padding:8px 10px;font-size:12px">${cl}</td>
        <td class="r" style="padding:8px 12px;white-space:nowrap">
          <div style="display:flex;align-items:center;justify-content:flex-end;gap:8px">
            <div style="width:72px;height:5px;background:#21262d;border-radius:3px;flex-shrink:0">
              <div style="width:${barW}%;height:100%;background:#3fb950;border-radius:3px"></div>
            </div>
            <span style="font-variant-numeric:tabular-nums;font-size:13px;font-weight:600;min-width:48px;text-align:right">${fmtNum(v.li,1)}</span>
          </div>
        </td>
        <td class="r" style="padding:8px 12px">${pctHtml}</td>`;
      tbody.appendChild(tr);
    });
    // Fila total
    const trT = document.createElement('tr');
    trT.className = 'tr-total';
    const totCmpLi = Object.values(clDataCmp).reduce((s,v) => s + v.li, 0);
    let totPctHtml;
    if (totCmpLi > 0) {
      const pp  = (totLi - totCmpLi) / totCmpLi * 100;
      const cls = pp >= 0 ? 'pct-up' : 'pct-dn';
      totPctHtml = `<span class="pct-badge ${cls}">${pp>=0?'+':''}${pp.toFixed(1)}%</span>`;
    } else {
      totPctHtml = `<span style="color:#484f58;font-size:11px">—</span>`;
    }
    trT.innerHTML = `
      <td style="padding:9px 4px"></td>
      <td style="padding:9px 10px;color:#e8d5a3;font-weight:800;font-size:12px">Total</td>
      <td class="r" style="padding:9px 12px;font-variant-numeric:tabular-nums;font-size:13px;font-weight:800;color:#e8d5a3">${fmtNum(totLi,1)}</td>
      <td class="r" style="padding:9px 12px">${totPctHtml}</td>`;
    tbody.appendChild(trT);
  }

  // ── Donuts ─────────────────────────────────────────────────────
  loadChartJS(function() {
    if (typeof Chart === 'undefined') return;

    // Mix Producto
    const prodLabels = [], prodData = [], prodColors = [];
    BOS_GENERAL_PRODUCTS.forEach(p => {
      const li = faMap[p.fa]?.li || 0;
      if (li > 0) { prodLabels.push(p.label); prodData.push(Math.round(li*10)/10); prodColors.push(p.color); }
    });
    const canvP = document.getElementById('bos-chart-prod');
    if (canvP) {
      if (canvP._chart) canvP._chart.destroy();
      canvP._chart = new Chart(canvP, {
        type: 'doughnut',
        data: { labels: prodLabels, datasets: [{ data: prodData, backgroundColor: prodColors, borderWidth: 2, borderColor: '#0d1117' }] },
        options: {
          responsive: true, maintainAspectRatio: false, cutout: '62%',
          plugins: {
            legend: { position:'bottom', labels: { color:'#c9d1d9', font:{size:11}, padding:12, boxWidth:12 } },
            tooltip: { callbacks: { label: ctx => ` ${ctx.label}: ${ctx.parsed.toLocaleString('es-AR',{maximumFractionDigits:1})} L` } }
          }
        }
      });
    }

    // Mix Canal
    const canalEntries = Object.entries(clData).sort((a,b) => b[1].li - a[1].li);
    const TOP = 5;
    const canalLabels = [], canalData = [];
    const CANAL_COLORS = ['#3fb950','#56d068','#7eda8a','#a0e6ac','#c0f0c8','#8b949e'];
    let otrosTotal = 0;
    canalEntries.forEach(([cl, v], i) => {
      if (i < TOP) { canalLabels.push(cl); canalData.push(Math.round(v.li*10)/10); }
      else otrosTotal += v.li;
    });
    if (otrosTotal > 0) { canalLabels.push('Otros'); canalData.push(Math.round(otrosTotal*10)/10); }
    const canvC = document.getElementById('bos-chart-canal');
    if (canvC) {
      if (canvC._chart) canvC._chart.destroy();
      canvC._chart = new Chart(canvC, {
        type: 'doughnut',
        data: { labels: canalLabels, datasets: [{ data: canalData, backgroundColor: CANAL_COLORS.slice(0, canalData.length), borderWidth: 2, borderColor: '#0d1117' }] },
        options: {
          responsive: true, maintainAspectRatio: false, cutout: '62%',
          plugins: {
            legend: { position:'bottom', labels: { color:'#c9d1d9', font:{size:11}, padding:12, boxWidth:12 } },
            tooltip: { callbacks: { label: ctx => ` ${ctx.label}: ${ctx.parsed.toLocaleString('es-AR',{maximumFractionDigits:1})} L` } }
          }
        }
      });
    }
  });
  renderObjPanel('bosque', bRows, 'bosque-obj-panel');
}

// ── Gauge SVG ────────────────────────────────────────────────
function renderBosqueGauge(value, yoyVal, popVal) {
  // Max dinámico: al menos 200% del valor actual, redondeado a centena
  const GAUGE_MAX = Math.max(Math.ceil(value * 1.6 / 100) * 100, 200);
  const p = Math.min(value / GAUGE_MAX, 1);
  const angle = -Math.PI + Math.PI * p;
  const ex = 100 + 80 * Math.cos(angle);
  const ey = 100 + 80 * Math.sin(angle);
  const largeArc = p >= 0.9999 ? 1 : 0;
  const arcPath = p < 0.001
    ? 'M 20 100'
    : `M 20 100 A 80 80 0 ${largeArc} 1 ${ex.toFixed(2)} ${ey.toFixed(2)}`;

  const arcEl = document.getElementById('bos-gauge-arc');
  if (arcEl) arcEl.setAttribute('d', arcPath);

  const valEl = document.getElementById('bos-gauge-val');
  if (valEl) valEl.textContent = fmtNum(value);

  const maxEl = document.getElementById('bos-gauge-max-lbl');
  if (maxEl) maxEl.textContent = GAUGE_MAX >= 1000
    ? (GAUGE_MAX/1000).toFixed(GAUGE_MAX%1000===0?0:1)+' mil'
    : GAUGE_MAX;

  const badgeEl = document.getElementById('bos-env-badge');
  if (badgeEl) {
    let html = '';
    if (yoyVal > 0) {
      const pct = ((value - yoyVal) / yoyVal * 100);
      const cls = pct >= 0 ? '#6ee7b7' : '#fca5a5';
      html += `<span style="color:${cls};font-size:13px;font-weight:700">${pct>=0?'+':''}${pct.toFixed(1)}%</span>`
            + `<span style="color:#6e7681;font-size:10px;margin-left:4px">aa</span>`;
    } else {
      html += '<span style="color:#6e7681;font-size:10px">— aa</span>';
    }
    if (popVal > 0) {
      const pct2 = ((value - popVal) / popVal * 100);
      const cls2 = pct2 >= 0 ? '#60a5fa' : '#fca5a5';
      html += `<br><span style="color:${cls2};font-size:12px;font-weight:700">${pct2>=0?'+':''}${pct2.toFixed(1)}%</span>`
            + `<span style="color:#6e7681;font-size:10px;margin-left:4px">per. ant.</span>`;
    }
    badgeEl.innerHTML = html;
  }
}

// ── Lista de productos ────────────────────────────────────────
function renderBosqueProductList(fa, faYoY) {
  const container = document.getElementById('bos-prod-list');
  if (!container) return;
  container.innerHTML = '';

  BOS_PRODUCTS.forEach(prod => {
    const li    = fa[prod.fa]?.li    || 0;
    const ce    = fa[prod.fa]?.ce    || 0;
    const liYoY = faYoY[prod.fa]?.li || 0;
    const ceYoY = faYoY[prod.fa]?.ce || 0;

    const item = document.createElement('div');
    item.className = 'bos-prod-item';

    // Ícono
    const icon = document.createElement('div');
    icon.className = 'bos-prod-icon';
    icon.style.cssText = `background:${prod.bg};color:${prod.color}`;
    icon.textContent = prod.label.substring(0,3);

    // Info
    const info = document.createElement('div');
    info.className = 'bos-prod-info';

    const name = document.createElement('div');
    name.className = 'bos-prod-name';
    name.style.color = prod.color;
    name.textContent = prod.label;

    if (li > 0 || ce > 0) {
      // Métricas: litros y envases
      const metrics = document.createElement('div');
      metrics.style.cssText = 'display:flex;gap:10px;align-items:baseline;margin:2px 0';

      const liEl = document.createElement('div');
      liEl.innerHTML = `<span style="font-size:16px;font-weight:900;color:#e6edf3">${fmtNum(li,1)}</span>`
        + `<span style="font-size:9px;color:#6e7681;margin-left:2px">L</span>`;

      const ceEl = document.createElement('div');
      ceEl.innerHTML = `<span style="font-size:13px;font-weight:700;color:#c9d1d9">${fmtNum(ce)}</span>`
        + `<span style="font-size:9px;color:#6e7681;margin-left:2px">env</span>`;

      metrics.appendChild(liEl);
      metrics.appendChild(ceEl);

      // Badge comparativo (litros aa)
      const badge = document.createElement('div');
      badge.className = 'bos-prod-badge';
      if (liYoY > 0) {
        const pct = ((li - liYoY) / liYoY * 100);
        badge.style.color = pct >= 0 ? '#6ee7b7' : '#fca5a5';
        badge.textContent = (pct >= 0 ? '+' : '') + pct.toFixed(1) + '% aa';
      } else {
        badge.style.color = '#6e7681';
        badge.textContent = '—';
      }

      info.appendChild(name);
      info.appendChild(metrics);
      info.appendChild(badge);
    } else {
      // Sin datos
      const empty = document.createElement('div');
      empty.style.cssText = 'font-size:18px;font-weight:900;color:#6e7681';
      empty.textContent = '—';
      info.appendChild(name);
      info.appendChild(empty);
    }

    item.appendChild(icon);
    item.appendChild(info);
    container.appendChild(item);
  });
}

// ── KPIs Litros + Envases ─────────────────────────────────────
function renderBosqueKPIs(totalLit, totalLitYoY, totalLitPop, totalEnv, totalEnvYoY, totalEnvPop) {
  function setKpiPair(valId, yoyId, popId, val, yoyVal, popVal, dec) {
    const vEl = document.getElementById(valId);
    if (vEl) vEl.textContent = fmtNum(val, dec);
    const yEl = document.getElementById(yoyId);
    if (yEl) {
      if (yoyVal > 0) {
        const pct = ((val - yoyVal) / yoyVal * 100);
        const cls = pct >= 0 ? '#6ee7b7' : '#fca5a5';
        yEl.innerHTML = `<span style="color:${cls};font-size:13px;font-weight:700">${pct>=0?'+':''}${pct.toFixed(1)}%</span>`
          + `<span style="color:#6e7681;font-size:10px;margin-left:4px">aa</span>`;
      } else {
        yEl.innerHTML = '<span style="color:#6e7681;font-size:10px">— aa</span>';
      }
    }
    const pEl = document.getElementById(popId);
    if (pEl) {
      if (popVal > 0) {
        const pct2 = ((val - popVal) / popVal * 100);
        const cls2 = pct2 >= 0 ? '#60a5fa' : '#fca5a5';
        pEl.innerHTML = `<span style="color:${cls2};font-size:12px;font-weight:700">${pct2>=0?'+':''}${pct2.toFixed(1)}%</span>`
          + `<span style="color:#6e7681;font-size:10px;margin-left:4px">per. ant.</span>`;
      } else {
        pEl.innerHTML = '<span style="color:#6e7681;font-size:10px">— per. ant.</span>';
      }
    }
  }
  setKpiPair('bos-kpi-lit', 'bos-kpi-lit-yoy', 'bos-kpi-lit-pop', totalLit, totalLitYoY, totalLitPop, 1);
  setKpiPair('bos-kpi-env', 'bos-kpi-env-yoy', 'bos-kpi-env-pop', totalEnv, totalEnvYoY, totalEnvPop, 0);
}

// ── Tabla de canales ──────────────────────────────────────────
function renderBosqueCanalTable(rows, rowsYoY) {
  const data    = byKey(rows,    'cl');
  const dataYoY = byKey(rowsYoY, 'cl');
  const sorted  = Object.entries(data).sort((a,b) => b[1].li - a[1].li);
  const totLi   = sorted.reduce((s,[,v]) => s + v.li, 0);
  const totCe   = sorted.reduce((s,[,v]) => s + v.ce, 0);
  const totYoYLi = Object.values(dataYoY).reduce((s,v) => s + v.li, 0);

  const tbody = document.getElementById('bos-tbl-body');
  if (!tbody) return;
  tbody.innerHTML = '';

  sorted.forEach(([cl, v], i) => {
    const prevLi = dataYoY[cl]?.li || 0;
    const barPct = totLi > 0 ? (v.li / totLi * 100).toFixed(1) : 0;

    // Badge % comparativo
    let pctBadge;
    if (prevLi > 0) {
      const p = ((v.li - prevLi) / prevLi * 100);
      const cls = p >= 0 ? 'pct-up' : 'pct-dn';
      pctBadge = `<span class="pct-badge ${cls}">${p>=0?'+':''}${p.toFixed(1)}%</span>`;
    } else {
      pctBadge = `<span class="pct-na">—</span>`;
    }

    const tr = document.createElement('tr');
    tr.innerHTML = `
      <td style="color:#6e7681;font-size:10px;padding-right:4px">${i+1}</td>
      <td>
        <div style="font-size:12px;color:#e6edf3;font-weight:500">${cl}</div>
        <div class="canal-bar-track"><div class="canal-bar-fill" style="width:${barPct}%"></div></div>
      </td>
      <td class="r">
        <span style="font-size:13px;font-weight:800;color:#e6edf3">${fmtNum(v.li,1)}</span>
        <span style="font-size:9px;color:#6e7681;margin-left:2px">L</span>
      </td>
      <td class="r">
        <span style="font-size:12px;font-weight:600;color:#c9d1d9">${fmtNum(v.ce)}</span>
        <span style="font-size:9px;color:#6e7681;margin-left:2px">env</span>
      </td>
      <td class="r">${pctBadge}</td>`;
    tbody.appendChild(tr);
  });

  // Fila total
  const trT = document.createElement('tr');
  trT.className = 'tr-total';
  const totPctBadge = totYoYLi > 0
    ? (() => { const p=((totLi-totYoYLi)/totYoYLi*100); const c=p>=0?'pct-up':'pct-dn'; return `<span class="pct-badge ${c}">${p>=0?'+':''}${p.toFixed(1)}%</span>`; })()
    : `<span class="pct-na">—</span>`;
  trT.innerHTML = `
    <td></td>
    <td style="font-size:12px">Total</td>
    <td class="r">
      <span style="font-size:13px">${fmtNum(totLi,1)}</span>
      <span style="font-size:9px;color:#9d4545;margin-left:2px">L</span>
    </td>
    <td class="r">
      <span style="font-size:12px">${fmtNum(totCe)}</span>
      <span style="font-size:9px;color:#9d4545;margin-left:2px">env</span>
    </td>
    <td class="r">${totPctBadge}</td>`;
  tbody.appendChild(trT);
}

// ── Bosque · Precio Promedio por Clusterización ───────────────
function renderBosquePrecio(rows, rowsPop) {
  const wrap = document.getElementById('bosque-precio-tbl-wrap');
  if (!wrap) return;

  const bRows    = rows.filter(r => BOS_KEYS.includes(r.fa));
  const bRowsPop = rowsPop.filter(r => BOS_KEYS.includes(r.fa));

  // Agregar por cluster
  function aggByCl(arr) {
    const m = {};
    arr.forEach(r => {
      if (!m[r.cl]) m[r.cl] = { li: 0, to: 0 };
      m[r.cl].li += r.li;
      m[r.cl].to += r.to;
    });
    return m;
  }
  const cur = aggByCl(bRows);
  const prv = aggByCl(bRowsPop);

  // Totales generales
  const totLi  = bRows.reduce((s,r) => s + r.li, 0);
  const totTo  = bRows.reduce((s,r) => s + r.to, 0);
  const pLiPrv = bRowsPop.reduce((s,r) => s + r.li, 0);
  const pToPrv = bRowsPop.reduce((s,r) => s + r.to, 0);

  // Precio promedio = $ / litro
  const pp = (to, li) => li > 0 ? to / li : 0;

  // Ordenar por litros desc
  const sortedCl = Object.keys(cur).sort((a, b) => cur[b].li - cur[a].li);

  // Delta helper
  function delta(cur, prv) {
    if (!prv || prv === 0) return null;
    return (cur - prv) / prv;
  }
  function deltaBadge(d) {
    if (d === null) return `<span style="color:#484f58">—</span>`;
    const pct = (d * 100).toFixed(1);
    const up  = d >= 0;
    const col = up ? '#6ee7b7' : '#fca5a5';
    const bg  = up ? '#064e3b' : '#450a0a';
    const arr = up ? '↑' : '↓';
    return `<span style="display:inline-block;padding:2px 7px;border-radius:99px;background:${bg};color:${col};font-size:10px;font-weight:700;letter-spacing:.2px">${up?'+':''}${pct}% ${arr}</span>`;
  }

  // ── Construir tabla ─────────────────────────────────────────
  let html = `
  <table style="width:100%;border-collapse:separate;border-spacing:0;font-size:12px">
    <thead>
      <tr>
        <th style="width:32px;padding:10px 8px;background:#1a1608;color:#6e7681;font-size:10px;font-weight:700;text-align:center;border-bottom:2px solid #3d2f0a">#</th>
        <th style="padding:10px 14px;background:#1a1608;color:#e8d5a3;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;text-align:left;border-bottom:2px solid #3d2f0a">Clusterización</th>
        <th style="padding:10px 14px;background:#1a1608;color:#e8d5a3;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;text-align:right;border-bottom:2px solid #3d2f0a">Litros ↓</th>
        <th style="padding:10px 14px;background:#1a1608;color:#e8d5a3;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;text-align:center;border-bottom:2px solid #3d2f0a">% Δ Litros</th>
        <th style="padding:10px 14px;background:#1a1608;color:#e8d5a3;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;text-align:right;border-bottom:2px solid #3d2f0a">Precio Promedio</th>
        <th style="padding:10px 14px;background:#1a1608;color:#e8d5a3;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;text-align:center;border-bottom:2px solid #3d2f0a">% Δ Precio</th>
      </tr>
    </thead>
    <tbody>`;

  sortedCl.forEach((cl, i) => {
    const c  = cur[cl];
    const p  = prv[cl] || { li: 0, to: 0 };
    const ppCur = pp(c.to, c.li);
    const ppPrv = pp(p.to, p.li);
    const dLi   = delta(c.li, p.li);
    const dPp   = delta(ppCur, ppPrv);
    const bg    = i % 2 === 0 ? '#0d1117' : '#161b22';
    html += `
      <tr style="background:${bg}">
        <td style="padding:10px 8px;text-align:center;color:#484f58;font-size:11px;border-bottom:1px solid #21262d">${i+1}.</td>
        <td style="padding:10px 14px;color:#e6edf3;font-weight:500;border-bottom:1px solid #21262d">${cl}</td>
        <td style="padding:10px 14px;text-align:right;color:#e6edf3;font-variant-numeric:tabular-nums;border-bottom:1px solid #21262d">${c.li.toLocaleString('es-AR',{maximumFractionDigits:0})}</td>
        <td style="padding:10px 14px;text-align:center;border-bottom:1px solid #21262d">${deltaBadge(dLi)}</td>
        <td style="padding:10px 14px;text-align:right;color:#e8d5a3;font-weight:700;font-variant-numeric:tabular-nums;border-bottom:1px solid #21262d">$ ${Math.round(ppCur).toLocaleString('es-AR')}</td>
        <td style="padding:10px 14px;text-align:center;border-bottom:1px solid #21262d">${deltaBadge(dPp)}</td>
      </tr>`;
  });

  // Fila total
  const ppTot    = pp(totTo, totLi);
  const ppTotPrv = pp(pToPrv, pLiPrv);
  html += `
    </tbody>
    <tfoot>
      <tr>
        <td style="padding:12px 8px;background:#1a1608;border-top:2px solid #3d2f0a"></td>
        <td style="padding:12px 14px;background:#1a1608;color:#e8d5a3;font-weight:900;font-size:12px;text-transform:uppercase;letter-spacing:.5px;border-top:2px solid #3d2f0a">Total</td>
        <td style="padding:12px 14px;text-align:right;background:#1a1608;color:#e8d5a3;font-weight:900;font-variant-numeric:tabular-nums;border-top:2px solid #3d2f0a">${totLi.toLocaleString('es-AR',{maximumFractionDigits:0})}</td>
        <td style="padding:12px 14px;text-align:center;background:#1a1608;border-top:2px solid #3d2f0a">${deltaBadge(delta(totLi, pLiPrv))}</td>
        <td style="padding:12px 14px;text-align:right;background:#1a1608;color:#e8d5a3;font-weight:900;font-variant-numeric:tabular-nums;border-top:2px solid #3d2f0a">$ ${Math.round(ppTot).toLocaleString('es-AR')}</td>
        <td style="padding:12px 14px;text-align:center;background:#1a1608;border-top:2px solid #3d2f0a">${deltaBadge(delta(ppTot, ppTotPrv))}</td>
      </tr>
    </tfoot>
  </table>`;

  wrap.innerHTML = html;
}

// ── Feriado · Precio Promedio por Clusterización ──────────────
function renderFeriadoPrecio(rows, cmpRows, cmpLabel) {
  const wrap = document.getElementById('feriado-precio-tbl-wrap');
  if (!wrap) return;

  const fRows    = rows.filter(r => FER_KEYS.includes(r.fa));
  const fRowsCmp = cmpRows.filter(r => FER_KEYS.includes(r.fa));

  // Agregar por cluster
  function aggByCl(arr) {
    const m = {};
    arr.forEach(r => {
      if (!m[r.cl]) m[r.cl] = { li: 0, to: 0 };
      m[r.cl].li += r.li;
      m[r.cl].to += r.to;
    });
    return m;
  }
  const cur = aggByCl(fRows);
  const prv = aggByCl(fRowsCmp);

  // Totales generales
  const totLi  = fRows.reduce((s,r) => s + r.li, 0);
  const totTo  = fRows.reduce((s,r) => s + r.to, 0);
  const pLiPrv = fRowsCmp.reduce((s,r) => s + r.li, 0);
  const pToPrv = fRowsCmp.reduce((s,r) => s + r.to, 0);

  // Precio promedio = $ / litro
  const pp = (to, li) => li > 0 ? to / li : 0;

  // Ordenar por litros desc
  const sortedCl = Object.keys(cur).sort((a, b) => cur[b].li - cur[a].li);

  // Delta helpers
  function delta(cur, prv) {
    if (!prv || prv === 0) return null;
    return (cur - prv) / prv;
  }
  function deltaBadge(d) {
    if (d === null) return `<span style="color:#484f58">—</span>`;
    const pct = (d * 100).toFixed(1);
    const up  = d >= 0;
    const col = up ? '#6ee7b7' : '#fca5a5';
    const bg  = up ? '#064e3b' : '#450a0a';
    const arr = up ? '↑' : '↓';
    return `<span style="display:inline-block;padding:2px 7px;border-radius:99px;background:${bg};color:${col};font-size:10px;font-weight:700;letter-spacing:.2px">${up?'+':''}${pct}% ${arr}</span>`;
  }

  // ── Construir tabla ─────────────────────────────────────────
  let html = `
  <table style="width:100%;border-collapse:separate;border-spacing:0;font-size:12px">
    <thead>
      <tr>
        <th style="width:32px;padding:10px 8px;background:#1a0408;color:#6e7681;font-size:10px;font-weight:700;text-align:center;border-bottom:2px solid #4a0a16">#</th>
        <th style="padding:10px 14px;background:#1a0408;color:#e8d5a3;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;text-align:left;border-bottom:2px solid #4a0a16">Clusterización</th>
        <th style="padding:10px 14px;background:#1a0408;color:#e8d5a3;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;text-align:right;border-bottom:2px solid #4a0a16">Litros ↓</th>
        <th style="padding:10px 14px;background:#1a0408;color:#e8d5a3;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;text-align:center;border-bottom:2px solid #4a0a16">% Δ Litros</th>
        <th style="padding:10px 14px;background:#1a0408;color:#e8d5a3;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;text-align:right;border-bottom:2px solid #4a0a16">Precio Promedio</th>
        <th style="padding:10px 14px;background:#1a0408;color:#e8d5a3;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;text-align:center;border-bottom:2px solid #4a0a16">% Δ Precio</th>
      </tr>
    </thead>
    <tbody>`;

  sortedCl.forEach((cl, i) => {
    const c  = cur[cl];
    const p  = prv[cl] || { li: 0, to: 0 };
    const ppCur = pp(c.to, c.li);
    const ppPrv = pp(p.to, p.li);
    const dLi   = delta(c.li, p.li);
    const dPp   = delta(ppCur, ppPrv);
    const bg    = i % 2 === 0 ? '#0d1117' : '#160a0c';
    html += `
      <tr style="background:${bg}">
        <td style="padding:10px 8px;text-align:center;color:#484f58;font-size:11px;border-bottom:1px solid #21262d">${i+1}.</td>
        <td style="padding:10px 14px;color:#e6edf3;font-weight:500;border-bottom:1px solid #21262d">${cl}</td>
        <td style="padding:10px 14px;text-align:right;color:#e6edf3;font-variant-numeric:tabular-nums;border-bottom:1px solid #21262d">${c.li.toLocaleString('es-AR',{maximumFractionDigits:0})}</td>
        <td style="padding:10px 14px;text-align:center;border-bottom:1px solid #21262d">${deltaBadge(dLi)}</td>
        <td style="padding:10px 14px;text-align:right;color:#e8d5a3;font-weight:700;font-variant-numeric:tabular-nums;border-bottom:1px solid #21262d">$ ${Math.round(ppCur).toLocaleString('es-AR')}</td>
        <td style="padding:10px 14px;text-align:center;border-bottom:1px solid #21262d">${deltaBadge(dPp)}</td>
      </tr>`;
  });

  // Fila total
  const ppTot    = pp(totTo, totLi);
  const ppTotPrv = pp(pToPrv, pLiPrv);
  html += `
    </tbody>
    <tfoot>
      <tr>
        <td style="padding:12px 8px;background:#1a0408;border-top:2px solid #4a0a16"></td>
        <td style="padding:12px 14px;background:#1a0408;color:#e8d5a3;font-weight:900;font-size:12px;text-transform:uppercase;letter-spacing:.5px;border-top:2px solid #4a0a16">Total</td>
        <td style="padding:12px 14px;text-align:right;background:#1a0408;color:#e8d5a3;font-weight:900;font-variant-numeric:tabular-nums;border-top:2px solid #4a0a16">${totLi.toLocaleString('es-AR',{maximumFractionDigits:0})}</td>
        <td style="padding:12px 14px;text-align:center;background:#1a0408;border-top:2px solid #4a0a16">${deltaBadge(delta(totLi, pLiPrv))}</td>
        <td style="padding:12px 14px;text-align:right;background:#1a0408;color:#e8d5a3;font-weight:900;font-variant-numeric:tabular-nums;border-top:2px solid #4a0a16">$ ${Math.round(ppTot).toLocaleString('es-AR')}</td>
        <td style="padding:12px 14px;text-align:center;background:#1a0408;border-top:2px solid #4a0a16">${deltaBadge(delta(ppTot, ppTotPrv))}</td>
      </tr>
    </tfoot>
  </table>`;

  wrap.innerHTML = html;
}

// ── Bosque · Clientes activos por semana (colapsable) ─────────
function renderBosqueClientesSemana(rows) {
  const tbl = document.getElementById('bosque-clientes-semana-tbl');
  if (!tbl) return;
  tbl.innerHTML = '';

  const bRows = rows.filter(r => BOS_KEYS.includes(r.fa));
  if (!bRows.length) {
    tbl.innerHTML = '<tr><td style="color:#8b949e;padding:20px">Sin datos para el período seleccionado.</td></tr>';
    return;
  }

  // Semanas únicas ordenadas desc
  // isoWeekKey se define más abajo — llamamos la versión inline aquí para independencia
  const wkOf = d => {
    const dt = new Date(d);
    const thu = new Date(dt); thu.setDate(dt.getDate() - ((dt.getDay()+6)%7) + 3);
    const y = thu.getFullYear();
    const jan4 = new Date(y,0,4);
    const w = 1 + Math.round(((thu-jan4)/86400000 - 3 + ((jan4.getDay()+6)%7))/7);
    return `${y}-W${String(w).padStart(2,'0')}`;
  };

  const semanas = [...new Set(bRows.map(r => wkOf(r.f)))].sort().reverse();

  // tree: cl → nd → Set<semana>
  const tree = {};
  bRows.forEach(r => {
    const wk = wkOf(r.f);
    if (!tree[r.cl]) tree[r.cl] = {};
    if (!tree[r.cl][r.nd]) tree[r.cl][r.nd] = new Set();
    tree[r.cl][r.nd].add(wk);
  });

  // Conteo de clientes distintos por semana (global, para total row)
  const colTotClientes = {};
  semanas.forEach(wk => {
    colTotClientes[wk] = new Set(bRows.filter(r => wkOf(r.f) === wk).map(r => r.nd)).size;
  });
  const maxClientes = Math.max(1, ...Object.values(colTotClientes));
  const totalDistinctClientes = new Set(bRows.map(r => r.nd)).size;

  // Año-grupos
  const yearGroups = [];
  semanas.forEach(wk => {
    const y = wk.slice(0,4);
    if (yearGroups.length && yearGroups[yearGroups.length-1].year === y)
      yearGroups[yearGroups.length-1].count++;
    else
      yearGroups.push({ year:y, count:1 });
  });

  const COL_W = '280px';
  const S_COL = `position:sticky;left:0;min-width:${COL_W};width:${COL_W};z-index:2;`;

  // ── THEAD ─────────────────────────────────────────────────────
  const thead = document.createElement('thead');
  const tr1 = document.createElement('tr');
  const thCl = document.createElement('th');
  thCl.rowSpan = 2;
  thCl.style.cssText = `${S_COL}position:sticky;top:0;background:#161b22;z-index:7;color:#e8d5a3;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;padding:7px 12px;border-bottom:2px solid #3d2f0a;text-align:left;`;
  thCl.textContent = 'Clusterización / Cliente';
  tr1.appendChild(thCl);
  yearGroups.forEach(g => {
    const th = document.createElement('th');
    th.colSpan = g.count;
    th.style.cssText = 'position:sticky;top:0;background:#1a1608;z-index:4;text-align:center;color:#e8d5a3;font-size:11px;font-weight:700;letter-spacing:1px;padding:5px 8px;border-bottom:1px solid #3d2f0a;';
    th.textContent = g.year;
    tr1.appendChild(th);
  });
  const thTotHdr = document.createElement('th');
  thTotHdr.rowSpan = 2;
  thTotHdr.style.cssText = 'position:sticky;top:0;right:0;background:#1a1608;z-index:6;text-align:right;color:#e8d5a3;font-size:11px;font-weight:700;padding:7px 14px;border-bottom:2px solid #3d2f0a;border-left:2px solid #3d2f0a;white-space:nowrap;';
  thTotHdr.textContent = 'Clientes';
  tr1.appendChild(thTotHdr);
  thead.appendChild(tr1);

  const tr2 = document.createElement('tr');
  semanas.forEach(wk => {
    const th = document.createElement('th');
    th.style.cssText = 'position:sticky;top:29px;background:#161b22;z-index:4;color:#c9a96e;font-size:11px;padding:4px 10px;text-align:right;white-space:nowrap;border-bottom:2px solid #3d2f0a;';
    th.textContent = parseInt(wk.slice(6), 10);
    tr2.appendChild(th);
  });
  thead.appendChild(tr2);
  tbl.appendChild(thead);

  // ── TBODY ─────────────────────────────────────────────────────
  const tbody = document.createElement('tbody');
  const sortedCl = Object.keys(tree).sort((a,b) => Object.keys(tree[b]).length - Object.keys(tree[a]).length);

  sortedCl.forEach(cl => {
    const nds = Object.keys(tree[cl]).sort((a,b) => tree[cl][b].size - tree[cl][a].size);
    const clId = 'ccs_' + cl.replace(/[^a-z0-9]/gi,'_');

    // Clientes activos por semana en este cluster
    const clCountWk = {};
    semanas.forEach(wk => {
      clCountWk[wk] = nds.filter(nd => tree[cl][nd].has(wk)).length;
    });

    // ── Fila cluster ──────────────────────────────────────────
    const trCl = document.createElement('tr');
    trCl.style.cursor = 'pointer';
    trCl.dataset.open = '0';

    const tdCl = document.createElement('td');
    tdCl.style.cssText = `${S_COL}background:#1a1608;color:#e8d5a3;font-size:11px;font-weight:700;padding:7px 12px;border-bottom:1px solid #21262d;text-align:left;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;`;
    tdCl.innerHTML = `<span id="${clId}-tog" style="display:inline-flex;align-items:center;justify-content:center;width:16px;height:16px;border:1px solid #3d2f0a;border-radius:3px;margin-right:8px;font-size:11px;font-weight:900;color:#e8d5a3;background:#2a1f08;vertical-align:middle;flex-shrink:0">+</span>${cl}`;
    trCl.appendChild(tdCl);

    semanas.forEach(wk => {
      const val = clCountWk[wk] || 0;
      const td = document.createElement('td');
      td.style.cssText = 'text-align:right;padding:7px 10px;font-size:11px;font-weight:700;border-bottom:1px solid #21262d;white-space:nowrap;font-variant-numeric:tabular-nums;';
      if (val > 0) {
        const alpha = 0.08 + (val / maxClientes) * 0.62;
        td.style.background = `rgba(110,231,183,${alpha.toFixed(2)})`;
        td.style.color = alpha > 0.45 ? '#061a10' : '#e6edf3';
        td.textContent = val;
      } else {
        td.style.color = '#30363d'; td.textContent = '—';
      }
      trCl.appendChild(td);
    });

    // Total = clientes distintos del cluster
    const tdClTot = document.createElement('td');
    tdClTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:7px 14px;font-size:11px;font-weight:800;color:#e8d5a3;background:#1a1608;border-bottom:1px solid #21262d;border-left:2px solid #3d2f0a;white-space:nowrap;font-variant-numeric:tabular-nums;';
    tdClTot.textContent = nds.length;
    trCl.appendChild(tdClTot);

    trCl.addEventListener('click', () => {
      const isOpen = trCl.dataset.open === '1';
      trCl.dataset.open = isOpen ? '0' : '1';
      const tog = document.getElementById(clId+'-tog');
      if (tog) tog.textContent = isOpen ? '+' : '−';
      tbody.querySelectorAll(`tr[data-parent="${clId}"]`).forEach(tr => {
        tr.style.display = isOpen ? 'none' : '';
      });
    });
    tbody.appendChild(trCl);

    // ── Sub-filas cliente: punto activo / guión ──────────────
    nds.forEach(nd => {
      const trNd = document.createElement('tr');
      trNd.dataset.parent = clId;
      trNd.style.display = 'none';

      const tdNd = document.createElement('td');
      tdNd.style.cssText = `${S_COL}background:#161b22;color:#c9d1d9;font-size:11px;padding:5px 12px 5px 38px;border-bottom:1px solid #1c2128;text-align:left;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;`;
      tdNd.textContent = nd;
      trNd.appendChild(tdNd);

      let activeSems = 0;
      semanas.forEach(wk => {
        const active = tree[cl][nd].has(wk);
        if (active) activeSems++;
        const td = document.createElement('td');
        td.style.cssText = 'text-align:center;padding:5px 10px;font-size:13px;border-bottom:1px solid #1c2128;white-space:nowrap;';
        if (active) {
          td.innerHTML = `<span style="color:#6ee7b7;font-size:10px">●</span>`;
        } else {
          td.innerHTML = `<span style="color:#30363d;font-size:11px">—</span>`;
        }
        trNd.appendChild(td);
      });

      // Total = semanas activas
      const tdNdTot = document.createElement('td');
      tdNdTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:5px 14px;font-size:11px;font-weight:600;color:#c9d1d9;background:#161b22;border-bottom:1px solid #1c2128;border-left:2px solid #21262d;white-space:nowrap;font-variant-numeric:tabular-nums;';
      tdNdTot.textContent = `${activeSems} sem.`;
      trNd.appendChild(tdNdTot);

      tbody.appendChild(trNd);
    });
  });

  // Fila grand total
  const trT = document.createElement('tr');
  const tdTotLbl = document.createElement('td');
  tdTotLbl.style.cssText = `${S_COL}background:#1a1608;color:#e8d5a3;font-size:11px;font-weight:900;padding:9px 12px;border-top:2px solid #3d2f0a;text-align:left;text-transform:uppercase;letter-spacing:.5px;`;
  tdTotLbl.textContent = 'Total';
  trT.appendChild(tdTotLbl);
  semanas.forEach(wk => {
    const val = colTotClientes[wk] || 0;
    const td = document.createElement('td');
    td.style.cssText = 'text-align:right;padding:9px 10px;font-size:11px;font-weight:800;color:#e8d5a3;background:#1a1608;border-top:2px solid #3d2f0a;white-space:nowrap;font-variant-numeric:tabular-nums;';
    td.textContent = val > 0 ? val : '—';
    trT.appendChild(td);
  });
  const tdGrandTot = document.createElement('td');
  tdGrandTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:9px 14px;font-size:12px;font-weight:900;color:#e8d5a3;background:#1a1608;border-top:2px solid #3d2f0a;border-left:2px solid #3d2f0a;white-space:nowrap;font-variant-numeric:tabular-nums;';
  tdGrandTot.textContent = totalDistinctClientes;
  trT.appendChild(tdGrandTot);
  tbody.appendChild(trT);
  tbl.appendChild(tbody);
}

// ── Feriado · Clientes activos por semana (colapsable) ────────
function renderFeriadoClientesSemana(rows) {
  const tbl = document.getElementById('feriado-clientes-semana-tbl');
  if (!tbl) return;
  tbl.innerHTML = '';

  const fRows = rows.filter(r => FER_KEYS.includes(r.fa));
  if (!fRows.length) {
    tbl.innerHTML = '<tr><td style="color:#8b949e;padding:20px">Sin datos para el período seleccionado.</td></tr>';
    return;
  }

  // Timezone-safe ISO week (fix UTC shift en Argentina)
  const wkOf = dateStr => {
    const [yr, mo, dy] = dateStr.split('-').map(Number);
    const dt = new Date(yr, mo - 1, dy);
    const thu = new Date(dt); thu.setDate(dt.getDate() - ((dt.getDay()+6)%7) + 3);
    const y = thu.getFullYear();
    const jan4 = new Date(y,0,4);
    const w = 1 + Math.round(((thu-jan4)/86400000 - 3 + ((jan4.getDay()+6)%7))/7);
    return `${y}-W${String(w).padStart(2,'0')}`;
  };

  const semanas = [...new Set(fRows.map(r => wkOf(r.f)))].sort().reverse();

  // tree: cl → nd → Set<semana>
  const tree = {};
  fRows.forEach(r => {
    const wk = wkOf(r.f);
    if (!tree[r.cl]) tree[r.cl] = {};
    if (!tree[r.cl][r.nd]) tree[r.cl][r.nd] = new Set();
    tree[r.cl][r.nd].add(wk);
  });

  // Conteo de clientes distintos por semana (global, para total row)
  const colTotClientes = {};
  semanas.forEach(wk => {
    colTotClientes[wk] = new Set(fRows.filter(r => wkOf(r.f) === wk).map(r => r.nd)).size;
  });
  const maxClientes = Math.max(1, ...Object.values(colTotClientes));
  const totalDistinctClientes = new Set(fRows.map(r => r.nd)).size;

  // Año-grupos
  const yearGroups = [];
  semanas.forEach(wk => {
    const y = wk.slice(0,4);
    if (yearGroups.length && yearGroups[yearGroups.length-1].year === y)
      yearGroups[yearGroups.length-1].count++;
    else
      yearGroups.push({ year:y, count:1 });
  });

  const COL_W = '280px';
  const S_COL = `position:sticky;left:0;min-width:${COL_W};width:${COL_W};z-index:2;`;

  // ── THEAD ──────────────────────────────────────────────────────
  const thead = document.createElement('thead');
  const tr1 = document.createElement('tr');
  const thCl = document.createElement('th');
  thCl.rowSpan = 2;
  thCl.style.cssText = `${S_COL}position:sticky;top:0;background:#161b22;z-index:7;color:#e8d5a3;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;padding:7px 12px;border-bottom:2px solid #4a0a16;text-align:left;`;
  thCl.textContent = 'Clusterización / Cliente';
  tr1.appendChild(thCl);
  yearGroups.forEach(g => {
    const th = document.createElement('th');
    th.colSpan = g.count;
    th.style.cssText = 'position:sticky;top:0;background:#1a0408;z-index:4;text-align:center;color:#e8d5a3;font-size:11px;font-weight:700;letter-spacing:1px;padding:5px 8px;border-bottom:1px solid #4a0a16;';
    th.textContent = g.year;
    tr1.appendChild(th);
  });
  const thTotHdr = document.createElement('th');
  thTotHdr.rowSpan = 2;
  thTotHdr.style.cssText = 'position:sticky;top:0;right:0;background:#1a0408;z-index:6;text-align:right;color:#e8d5a3;font-size:11px;font-weight:700;padding:7px 14px;border-bottom:2px solid #4a0a16;border-left:2px solid #4a0a16;white-space:nowrap;';
  thTotHdr.textContent = 'Clientes';
  tr1.appendChild(thTotHdr);
  thead.appendChild(tr1);

  const tr2 = document.createElement('tr');
  semanas.forEach(wk => {
    const th = document.createElement('th');
    th.style.cssText = 'position:sticky;top:29px;background:#161b22;z-index:4;color:#e8a0a0;font-size:11px;padding:4px 10px;text-align:right;white-space:nowrap;border-bottom:2px solid #4a0a16;';
    th.textContent = parseInt(wk.slice(6), 10);
    tr2.appendChild(th);
  });
  thead.appendChild(tr2);
  tbl.appendChild(thead);

  // ── TBODY ──────────────────────────────────────────────────────
  const tbody = document.createElement('tbody');
  const sortedCl = Object.keys(tree).sort((a,b) => Object.keys(tree[b]).length - Object.keys(tree[a]).length);

  sortedCl.forEach(cl => {
    const nds = Object.keys(tree[cl]).sort((a,b) => tree[cl][b].size - tree[cl][a].size);
    const clId = 'fcs_' + cl.replace(/[^a-z0-9]/gi,'_');

    // Clientes activos por semana en este cluster
    const clCountWk = {};
    semanas.forEach(wk => {
      clCountWk[wk] = nds.filter(nd => tree[cl][nd].has(wk)).length;
    });

    // ── Fila cluster ────────────────────────────────────────────
    const trCl = document.createElement('tr');
    trCl.style.cursor = 'pointer';
    trCl.dataset.open = '0';

    const tdCl = document.createElement('td');
    tdCl.style.cssText = `${S_COL}background:#1a0408;color:#e8d5a3;font-size:11px;font-weight:700;padding:7px 12px;border-bottom:1px solid #21262d;text-align:left;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;`;
    tdCl.innerHTML = `<span id="${clId}-tog" style="display:inline-flex;align-items:center;justify-content:center;width:16px;height:16px;border:1px solid #4a0a16;border-radius:3px;margin-right:8px;font-size:11px;font-weight:900;color:#e8d5a3;background:#2a080e;vertical-align:middle;flex-shrink:0">+</span>${cl}`;
    trCl.appendChild(tdCl);

    semanas.forEach(wk => {
      const val = clCountWk[wk] || 0;
      const td = document.createElement('td');
      td.style.cssText = 'text-align:right;padding:7px 10px;font-size:11px;font-weight:700;border-bottom:1px solid #21262d;white-space:nowrap;font-variant-numeric:tabular-nums;';
      if (val > 0) {
        const alpha = 0.08 + (val / maxClientes) * 0.62;
        td.style.background = `rgba(200,16,46,${alpha.toFixed(2)})`;
        td.style.color = alpha > 0.45 ? '#fce8eb' : '#e6edf3';
        td.textContent = val;
      } else {
        td.style.color = '#30363d'; td.textContent = '—';
      }
      trCl.appendChild(td);
    });

    // Total = clientes distintos del cluster
    const tdClTot = document.createElement('td');
    tdClTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:7px 14px;font-size:11px;font-weight:800;color:#e8d5a3;background:#1a0408;border-bottom:1px solid #21262d;border-left:2px solid #4a0a16;white-space:nowrap;font-variant-numeric:tabular-nums;';
    tdClTot.textContent = nds.length;
    trCl.appendChild(tdClTot);

    trCl.addEventListener('click', () => {
      const isOpen = trCl.dataset.open === '1';
      trCl.dataset.open = isOpen ? '0' : '1';
      const tog = document.getElementById(clId+'-tog');
      if (tog) tog.textContent = isOpen ? '+' : '−';
      tbody.querySelectorAll(`tr[data-parent="${clId}"]`).forEach(tr => {
        tr.style.display = isOpen ? 'none' : '';
      });
    });
    tbody.appendChild(trCl);

    // ── Sub-filas cliente ────────────────────────────────────────
    nds.forEach(nd => {
      const trNd = document.createElement('tr');
      trNd.dataset.parent = clId;
      trNd.style.display = 'none';

      const tdNd = document.createElement('td');
      tdNd.style.cssText = `${S_COL}background:#160a0c;color:#c9d1d9;font-size:11px;padding:5px 12px 5px 38px;border-bottom:1px solid #1c2128;text-align:left;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;`;
      tdNd.textContent = nd;
      trNd.appendChild(tdNd);

      let activeSems = 0;
      semanas.forEach(wk => {
        const active = tree[cl][nd].has(wk);
        if (active) activeSems++;
        const td = document.createElement('td');
        td.style.cssText = 'text-align:center;padding:5px 10px;font-size:13px;border-bottom:1px solid #1c2128;white-space:nowrap;';
        if (active) {
          td.innerHTML = `<span style="color:#fca5a5;font-size:10px">●</span>`;
        } else {
          td.innerHTML = `<span style="color:#30363d;font-size:11px">—</span>`;
        }
        trNd.appendChild(td);
      });

      // Total = semanas activas
      const tdNdTot = document.createElement('td');
      tdNdTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:5px 14px;font-size:11px;font-weight:600;color:#c9d1d9;background:#160a0c;border-bottom:1px solid #1c2128;border-left:2px solid #21262d;white-space:nowrap;font-variant-numeric:tabular-nums;';
      tdNdTot.textContent = `${activeSems} sem.`;
      trNd.appendChild(tdNdTot);

      tbody.appendChild(trNd);
    });
  });

  // Fila grand total
  const trT = document.createElement('tr');
  const tdTotLbl = document.createElement('td');
  tdTotLbl.style.cssText = `${S_COL}background:#1a0408;color:#e8d5a3;font-size:11px;font-weight:900;padding:9px 12px;border-top:2px solid #4a0a16;text-align:left;text-transform:uppercase;letter-spacing:.5px;`;
  tdTotLbl.textContent = 'Total';
  trT.appendChild(tdTotLbl);
  semanas.forEach(wk => {
    const val = colTotClientes[wk] || 0;
    const td = document.createElement('td');
    td.style.cssText = 'text-align:right;padding:9px 10px;font-size:11px;font-weight:800;color:#e8d5a3;background:#1a0408;border-top:2px solid #4a0a16;white-space:nowrap;font-variant-numeric:tabular-nums;';
    td.textContent = val > 0 ? val : '—';
    trT.appendChild(td);
  });
  const tdGrandTot = document.createElement('td');
  tdGrandTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:9px 14px;font-size:12px;font-weight:900;color:#e8d5a3;background:#1a0408;border-top:2px solid #4a0a16;border-left:2px solid #4a0a16;white-space:nowrap;font-variant-numeric:tabular-nums;';
  tdGrandTot.textContent = totalDistinctClientes;
  trT.appendChild(tdGrandTot);
  tbody.appendChild(trT);
  tbl.appendChild(tbody);
}

// ── Cerveza · Latas ───────────────────────────────────────────
function renderCervezaTab(rows, rowsYoY, rowsPop) {
  const LATA_KEYS = ['lata_wolf','lata_scottish','lata_golden','lata_wolf0','lata_otras'];
  const lRows = rows.filter(r    => LATA_KEYS.includes(r.fa));
  const lYoY  = (rowsYoY||[]).filter(r => LATA_KEYS.includes(r.fa));
  const lPop  = (rowsPop||[]).filter(r  => LATA_KEYS.includes(r.fa));

  const totCe    = lRows.reduce((s,r) => s+r.ce, 0);
  const totLi    = lRows.reduce((s,r) => s+r.li, 0);
  const yoyCe    = lYoY.reduce((s,r)  => s+r.ce, 0);
  const yoyLi    = lYoY.reduce((s,r)  => s+r.li, 0);
  const popCe    = lPop.reduce((s,r)   => s+r.ce, 0);
  const popLi    = lPop.reduce((s,r)   => s+r.li, 0);

  function dPct(cur, prv) { return prv ? (cur-prv)/prv : null; }
  function badge1(d, color) {
    if (d === null) return `<span style="color:#484f58">—</span>`;
    const p = (d*100).toFixed(1), up = d >= 0;
    return `<span style="display:inline-block;padding:2px 8px;border-radius:99px;background:${up?'#064e3b':'#450a0a'};color:${color||( up?'#6ee7b7':'#fca5a5')};font-size:11px;font-weight:700">${up?'+':''}${p}% ${up?'↑':'↓'}</span>`;
  }
  function dBadgeDual(yoyD, popD) {
    const aaHtml  = badge1(yoyD, yoyD  === null ? null : (yoyD  >= 0 ? '#6ee7b7' : '#fca5a5'));
    const popHtml = badge1(popD, popD  === null ? null : (popD  >= 0 ? '#93c5fd' : '#fca5a5'));
    return `<div style="display:flex;flex-direction:column;align-items:center;gap:4px">
      <div style="display:flex;align-items:center;gap:4px"><span style="font-size:10px;color:#6ee7b7;opacity:.7">aa</span>${aaHtml}</div>
      <div style="display:flex;align-items:center;gap:4px"><span style="font-size:10px;color:#93c5fd;opacity:.7">per. ant.</span>${popHtml}</div>
    </div>`;
  }

  // ── KPI cards ──────────────────────────────────────────────────
  const kpiWrap = document.getElementById('cerv-kpi-row');
  if (kpiWrap) kpiWrap.innerHTML = `
    <div style="background:#0c1f35;border:1px solid #1e3a5f;border-radius:12px;padding:18px 22px;text-align:center">
      <div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#38bdf8;margin-bottom:10px">Cantidad de Latas</div>
      <div style="font-size:36px;font-weight:900;color:#e6edf3;font-variant-numeric:tabular-nums">${totCe.toLocaleString('es-AR')}</div>
      <div style="margin-top:10px">${dBadgeDual(dPct(totCe,yoyCe), dPct(totCe,popCe))}</div>
    </div>
    <div style="background:#0c1f35;border:1px solid #1e3a5f;border-radius:12px;padding:18px 22px;text-align:center">
      <div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#38bdf8;margin-bottom:10px">Litros</div>
      <div style="font-size:36px;font-weight:900;color:#e6edf3;font-variant-numeric:tabular-nums">${totLi.toLocaleString('es-AR',{maximumFractionDigits:2})}</div>
      <div style="margin-top:10px">${dBadgeDual(dPct(totLi,yoyLi), dPct(totLi,popLi))}</div>
    </div>`;

  // ── Tarjetas de producto ────────────────────────────────────────
  const PRODS = [
    { fa:'lata_scottish', name:'Scottish',             color:'#7dd3fc', bg:'#07243b' },
    { fa:'lata_wolf',     name:'Wolf IPA',             color:'#38bdf8', bg:'#062033' },
    { fa:'lata_wolf0',    name:'Wolf 0% Alc.',         color:'#0284c7', bg:'#051828' },
    { fa:'lata_golden',   name:'Golden / Indie Ale',   color:'#f59e0b', bg:'#251800' },
    { fa:'lata_otras',    name:'Flow / Cósmica / Otras', color:'#6e7681', bg:'#161b22' },
  ];
  const byCurFa = {}, byYoyFa = {}, byPopFa = {};
  lRows.forEach(r => { byCurFa[r.fa] = (byCurFa[r.fa]||0) + r.ce; });
  lYoY.forEach(r  => { byYoyFa[r.fa] = (byYoyFa[r.fa]||0) + r.ce; });
  lPop.forEach(r  => { byPopFa[r.fa] = (byPopFa[r.fa]||0) + r.ce; });

  const prodWrap = document.getElementById('cerv-prod-row');
  if (prodWrap) prodWrap.innerHTML = PRODS.map(p => {
    const cur  = byCurFa[p.fa]||0;
    const yoyV = byYoyFa[p.fa]||0;
    const popV = byPopFa[p.fa]||0;
    return `<div style="flex:1;min-width:140px;background:${p.bg};border:1px solid rgba(255,255,255,.07);border-top:3px solid ${p.color};border-radius:10px;padding:14px 12px;text-align:center">
      <div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:${p.color};margin-bottom:10px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${p.name}</div>
      <div style="font-size:28px;font-weight:900;color:#e6edf3;font-variant-numeric:tabular-nums">${cur.toLocaleString('es-AR')}</div>
      <div style="font-size:10px;color:#6e7681;margin:3px 0 8px">latas</div>
      ${dBadgeDual(dPct(cur,yoyV), dPct(cur,popV))}
    </div>`;
  }).join('');

  // ── Ranking por cluster ─────────────────────────────────────────
  const rankWrap = document.getElementById('cerv-ranking-wrap');
  if (rankWrap) {
    const byCl = {}, byYoyCl = {}, byPopCl = {};
    lRows.forEach(r => { byCl[r.cl]    = (byCl[r.cl]||0)    + r.ce; });
    lYoY.forEach(r  => { byYoyCl[r.cl] = (byYoyCl[r.cl]||0) + r.ce; });
    lPop.forEach(r  => { byPopCl[r.cl] = (byPopCl[r.cl]||0) + r.ce; });
    const sorted = Object.entries(byCl).sort((a,b) => b[1]-a[1]);
    const maxCe  = sorted.length ? sorted[0][1] : 1;
    const totYoyCe = lYoY.reduce((s,r) => s+r.ce, 0);
    const totPopCe = lPop.reduce((s,r)  => s+r.ce, 0);

    let html = `<table style="width:100%;border-collapse:separate;border-spacing:0;font-size:12px">
      <thead><tr>
        <th style="width:28px;padding:9px 6px;background:#0c1f35;color:#6e7681;font-size:10px;font-weight:700;text-align:center;border-bottom:2px solid #1e3a5f">#</th>
        <th style="padding:9px 14px;background:#0c1f35;color:#bae6fd;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;text-align:left;border-bottom:2px solid #1e3a5f">Clusterización</th>
        <th style="padding:9px 14px;background:#0c1f35;color:#bae6fd;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;text-align:right;border-bottom:2px solid #1e3a5f">CantEnvases ↓</th>
        <th style="padding:9px 14px;background:#0c1f35;color:#bae6fd;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;text-align:center;border-bottom:2px solid #1e3a5f">% Δ</th>
      </tr></thead><tbody>`;

    sorted.forEach(([cl, val], i) => {
      const yoyV = byYoyCl[cl]||0;
      const popV = byPopCl[cl]||0;
      const barW = Math.round((val/maxCe)*100);
      const bg = i%2===0 ? '#0d1117' : '#0a1929';
      html += `<tr style="background:${bg}">
        <td style="padding:9px 6px;text-align:center;color:#484f58;font-size:11px;border-bottom:1px solid #1e2d40">${i+1}.</td>
        <td style="padding:9px 14px;color:#e6edf3;font-weight:500;border-bottom:1px solid #1e2d40">${cl}</td>
        <td style="padding:9px 14px;border-bottom:1px solid #1e2d40">
          <div style="display:flex;align-items:center;justify-content:flex-end;gap:8px">
            <div style="width:80px;height:5px;background:#1e2d40;border-radius:3px;flex-shrink:0">
              <div style="width:${barW}%;height:100%;background:#38bdf8;border-radius:3px"></div>
            </div>
            <span style="color:#e6edf3;font-variant-numeric:tabular-nums">${val.toLocaleString('es-AR')}</span>
          </div>
        </td>
        <td style="padding:9px 14px;text-align:center;border-bottom:1px solid #1e2d40">${dBadgeDual(dPct(val,yoyV), dPct(val,popV))}</td>
      </tr>`;
    });

    html += `</tbody><tfoot><tr>
      <td style="padding:10px 6px;background:#0c1f35;border-top:2px solid #1e3a5f"></td>
      <td style="padding:10px 14px;background:#0c1f35;color:#bae6fd;font-weight:900;font-size:12px;text-transform:uppercase;letter-spacing:.5px;border-top:2px solid #1e3a5f">Total</td>
      <td style="padding:10px 14px;text-align:right;background:#0c1f35;color:#bae6fd;font-weight:900;font-variant-numeric:tabular-nums;border-top:2px solid #1e3a5f">${totCe.toLocaleString('es-AR')}</td>
      <td style="padding:10px 14px;text-align:center;background:#0c1f35;border-top:2px solid #1e3a5f">${dBadgeDual(dPct(totCe,totYoyCe), dPct(totCe,totPopCe))}</td>
    </tr></tfoot></table>`;
    rankWrap.innerHTML = html;
  }

  // ── Pivot Mes × Cluster ─────────────────────────────────────────
  const tbl = document.getElementById('cerv-pivot-tbl');
  if (!tbl) return;
  tbl.innerHTML = '';

  if (!lRows.length) {
    tbl.innerHTML = '<tr><td style="color:#8b949e;padding:20px" colspan="20">Sin datos para el período seleccionado.</td></tr>';
    return;
  }

  const MNAMES = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
  const meses  = [...new Set(lRows.map(r => r.f.slice(0,7)))].sort().reverse();

  // tree: cl → nd → mes → sum(ce)
  const tree = {};
  lRows.forEach(r => {
    const m = r.f.slice(0,7);
    if (!tree[r.cl]) tree[r.cl] = {};
    if (!tree[r.cl][r.nd]) tree[r.cl][r.nd] = {};
    tree[r.cl][r.nd][m] = (tree[r.cl][r.nd][m]||0) + r.ce;
  });

  const colTot = {};
  let grandTotal = 0;
  meses.forEach(m => {
    colTot[m] = lRows.filter(r => r.f.slice(0,7)===m).reduce((s,r) => s+r.ce, 0);
    grandTotal += colTot[m];
  });
  const maxVal = Math.max(1, ...Object.values(colTot));

  const yearGroups = [];
  meses.forEach(m => {
    const y = m.slice(0,4);
    if (yearGroups.length && yearGroups[yearGroups.length-1].year === y) yearGroups[yearGroups.length-1].count++;
    else yearGroups.push({year:y, count:1});
  });

  const CL_W = '140px', ND_W = '175px';
  const sCL = `position:sticky;left:0;width:${CL_W};min-width:${CL_W};z-index:2;`;
  const sND = `position:sticky;left:${CL_W};width:${ND_W};min-width:${ND_W};z-index:2;`;

  // THEAD
  const thead = document.createElement('thead');
  const tr1 = document.createElement('tr');

  const thCl = document.createElement('th');
  thCl.rowSpan = 2;
  thCl.style.cssText = `${sCL}position:sticky;top:0;background:#0c1f35;z-index:7;color:#bae6fd;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;padding:7px 10px;border-bottom:2px solid #1e3a5f;text-align:left;border-right:1px solid #1e3a5f;`;
  thCl.innerHTML = `<span id="cerv-exp-all" style="display:inline-flex;align-items:center;justify-content:center;width:15px;height:15px;border:1px solid #1e3a5f;border-radius:2px;margin-right:7px;font-size:11px;font-weight:900;color:#bae6fd;background:#062033;vertical-align:middle;cursor:pointer;flex-shrink:0" title="Expandir/colapsar todo">−</span>Clusterización`;
  tr1.appendChild(thCl);

  const thNd = document.createElement('th');
  thNd.rowSpan = 2;
  thNd.style.cssText = `${sND}position:sticky;top:0;background:#0c1f35;z-index:7;color:#bae6fd;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;padding:7px 10px;border-bottom:2px solid #1e3a5f;text-align:left;border-right:1px solid #1e3a5f;`;
  thNd.textContent = 'NombreDeFantasía';
  tr1.appendChild(thNd);

  yearGroups.forEach(g => {
    const th = document.createElement('th');
    th.colSpan = g.count;
    th.style.cssText = 'position:sticky;top:0;background:#0c1f35;z-index:4;text-align:center;color:#bae6fd;font-size:11px;font-weight:700;letter-spacing:1px;padding:5px 8px;border-bottom:1px solid #1e3a5f;';
    th.textContent = g.year;
    tr1.appendChild(th);
  });

  const thTot = document.createElement('th');
  thTot.rowSpan = 2;
  thTot.style.cssText = 'position:sticky;top:0;right:0;background:#0c1f35;z-index:6;text-align:right;color:#bae6fd;font-size:10px;font-weight:700;padding:7px 12px;border-bottom:2px solid #1e3a5f;border-left:2px solid #1e3a5f;white-space:nowrap;';
  thTot.textContent = 'Total';
  tr1.appendChild(thTot);
  thead.appendChild(tr1);

  const tr2 = document.createElement('tr');
  meses.forEach(m => {
    const th = document.createElement('th');
    th.style.cssText = 'position:sticky;top:29px;background:#0c1f35;z-index:4;color:#7dd3fc;font-size:11px;padding:4px 10px;text-align:right;white-space:nowrap;border-bottom:2px solid #1e3a5f;';
    th.textContent = MNAMES[parseInt(m.slice(5,7),10)-1];
    tr2.appendChild(th);
  });
  thead.appendChild(tr2);
  tbl.appendChild(thead);

  // TBODY
  const tbody = document.createElement('tbody');
  const sortedCl = Object.keys(tree).sort((a,b) => {
    const s = k => meses.reduce((t,m) => t + Object.values(tree[k]).reduce((tt,nd) => tt+(nd[m]||0),0),0);
    return s(b)-s(a);
  });

  sortedCl.forEach(cl => {
    const nds = Object.keys(tree[cl]).sort((a,b) => {
      const tA = meses.reduce((s,m) => s+(tree[cl][a][m]||0),0);
      const tB = meses.reduce((s,m) => s+(tree[cl][b][m]||0),0);
      return tB-tA;
    });
    const clId = 'cerv_'+cl.replace(/[^a-z0-9]/gi,'_');

    const clTotMes = {}; let clTotAll = 0;
    meses.forEach(m => { clTotMes[m] = nds.reduce((s,nd)=>s+(tree[cl][nd][m]||0),0); clTotAll+=clTotMes[m]; });

    // Cluster header row
    const trCl = document.createElement('tr');
    trCl.dataset.open = '1';
    trCl.dataset.clId = clId;
    trCl.style.cursor = 'pointer';

    const tdCl1 = document.createElement('td');
    tdCl1.style.cssText = `${sCL}background:#0c1f35;color:#bae6fd;font-size:11px;font-weight:700;padding:7px 10px;border-bottom:1px solid #1e3a5f;border-right:1px solid #1e3a5f;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;`;
    tdCl1.innerHTML = `<span id="${clId}-tog" style="display:inline-flex;align-items:center;justify-content:center;width:14px;height:14px;border:1px solid #1e3a5f;border-radius:2px;margin-right:7px;font-size:10px;font-weight:900;color:#bae6fd;background:#062033;vertical-align:middle;flex-shrink:0">−</span>${cl}`;
    trCl.appendChild(tdCl1);

    const tdCl2 = document.createElement('td');
    tdCl2.style.cssText = `${sND}background:#0c1f35;border-bottom:1px solid #1e3a5f;border-right:1px solid #1e3a5f;`;
    trCl.appendChild(tdCl2);

    meses.forEach(m => {
      const val = clTotMes[m]||0;
      const td = document.createElement('td');
      td.style.cssText = 'text-align:right;padding:7px 10px;font-size:11px;font-weight:700;background:#0c1f35;border-bottom:1px solid #1e3a5f;white-space:nowrap;font-variant-numeric:tabular-nums;';
      td.style.color = val>0 ? '#e6edf3' : '#484f58';
      td.textContent = val>0 ? val.toLocaleString('es-AR') : '—';
      trCl.appendChild(td);
    });

    const tdClTot = document.createElement('td');
    tdClTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:7px 12px;font-size:11px;font-weight:800;color:#bae6fd;background:#0c1f35;border-bottom:1px solid #1e3a5f;border-left:2px solid #1e3a5f;white-space:nowrap;font-variant-numeric:tabular-nums;';
    tdClTot.textContent = clTotAll.toLocaleString('es-AR');
    trCl.appendChild(tdClTot);

    trCl.addEventListener('click', () => {
      const isOpen = trCl.dataset.open === '1';
      trCl.dataset.open = isOpen ? '0' : '1';
      const tog = document.getElementById(clId+'-tog');
      if (tog) tog.textContent = isOpen ? '+' : '−';
      tbody.querySelectorAll(`[data-parent="${clId}"]`).forEach(r => { r.style.display = isOpen ? 'none' : ''; });
    });
    tbody.appendChild(trCl);

    // Client sub-rows
    nds.forEach(nd => {
      let ndTot = 0;
      const trNd = document.createElement('tr');
      trNd.dataset.parent = clId;

      const tdN1 = document.createElement('td');
      tdN1.style.cssText = `${sCL}background:#0a1929;border-bottom:1px solid #1c2128;border-right:1px solid #1e3a5f;`;
      trNd.appendChild(tdN1);

      const tdN2 = document.createElement('td');
      tdN2.style.cssText = `${sND}background:#0a1929;color:#c9d1d9;font-size:11px;padding:5px 10px;border-bottom:1px solid #1c2128;border-right:1px solid #1e3a5f;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;`;
      tdN2.textContent = nd;
      trNd.appendChild(tdN2);

      meses.forEach(m => {
        const val = tree[cl][nd][m]||0;
        ndTot += val;
        const td = document.createElement('td');
        td.style.cssText = 'text-align:right;padding:5px 10px;font-size:11px;border-bottom:1px solid #1c2128;white-space:nowrap;font-variant-numeric:tabular-nums;';
        if (val > 0) {
          const alpha = 0.07 + (val/maxVal)*0.52;
          td.style.background = `rgba(56,189,248,${alpha.toFixed(2)})`;
          td.style.color = alpha > 0.42 ? '#02152b' : '#e6edf3';
          td.textContent = val.toLocaleString('es-AR');
        } else {
          td.style.color = '#30363d'; td.textContent = '—';
        }
        trNd.appendChild(td);
      });

      const tdNTot = document.createElement('td');
      tdNTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:5px 12px;font-size:11px;font-weight:600;color:#c9d1d9;background:#0a1929;border-bottom:1px solid #1c2128;border-left:2px solid #1e3a5f;white-space:nowrap;font-variant-numeric:tabular-nums;';
      tdNTot.textContent = ndTot > 0 ? ndTot.toLocaleString('es-AR') : '—';
      trNd.appendChild(tdNTot);
      tbody.appendChild(trNd);
    });

    // Subtotal row
    const trSub = document.createElement('tr');
    trSub.dataset.parent = clId;
    const tdS1 = document.createElement('td');
    tdS1.style.cssText = `${sCL}background:#0c1f35;border-bottom:2px solid #1e3a5f;border-right:1px solid #1e3a5f;`;
    trSub.appendChild(tdS1);
    const tdS2 = document.createElement('td');
    tdS2.style.cssText = `${sND}background:#0c1f35;color:#bae6fd;font-size:11px;font-weight:700;padding:6px 10px;border-bottom:2px solid #1e3a5f;border-right:1px solid #1e3a5f;letter-spacing:.3px;`;
    tdS2.textContent = 'Subtotal';
    trSub.appendChild(tdS2);
    meses.forEach(m => {
      const val = clTotMes[m]||0;
      const td = document.createElement('td');
      td.style.cssText = 'text-align:right;padding:6px 10px;font-size:11px;font-weight:700;color:#e6edf3;background:#0c1f35;border-bottom:2px solid #1e3a5f;white-space:nowrap;font-variant-numeric:tabular-nums;';
      td.textContent = val>0 ? val.toLocaleString('es-AR') : '—';
      trSub.appendChild(td);
    });
    const tdSTot = document.createElement('td');
    tdSTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:6px 12px;font-size:11px;font-weight:800;color:#bae6fd;background:#0c1f35;border-bottom:2px solid #1e3a5f;border-left:2px solid #1e3a5f;white-space:nowrap;font-variant-numeric:tabular-nums;';
    tdSTot.textContent = clTotAll.toLocaleString('es-AR');
    trSub.appendChild(tdSTot);
    tbody.appendChild(trSub);
  });

  // Grand total row
  const trG = document.createElement('tr');
  const tdG1 = document.createElement('td');
  tdG1.style.cssText = `${sCL}background:#0c1f35;color:#bae6fd;font-size:11px;font-weight:900;padding:9px 10px;border-top:2px solid #38bdf8;border-right:1px solid #1e3a5f;text-transform:uppercase;letter-spacing:.5px;`;
  tdG1.textContent = 'Total';
  trG.appendChild(tdG1);
  const tdG2 = document.createElement('td');
  tdG2.style.cssText = `${sND}background:#0c1f35;border-top:2px solid #38bdf8;border-right:1px solid #1e3a5f;`;
  trG.appendChild(tdG2);
  meses.forEach(m => {
    const val = colTot[m]||0;
    const td = document.createElement('td');
    td.style.cssText = 'text-align:right;padding:9px 10px;font-size:11px;font-weight:800;color:#bae6fd;background:#0c1f35;border-top:2px solid #38bdf8;white-space:nowrap;font-variant-numeric:tabular-nums;';
    td.textContent = val>0 ? val.toLocaleString('es-AR') : '—';
    trG.appendChild(td);
  });
  const tdGT = document.createElement('td');
  tdGT.style.cssText = 'position:sticky;right:0;text-align:right;padding:9px 12px;font-size:12px;font-weight:900;color:#bae6fd;background:#0c1f35;border-top:2px solid #38bdf8;border-left:2px solid #1e3a5f;white-space:nowrap;font-variant-numeric:tabular-nums;';
  tdGT.textContent = grandTotal.toLocaleString('es-AR');
  trG.appendChild(tdGT);
  tbody.appendChild(trG);
  tbl.appendChild(tbody);

  // Expand-all button
  const expBtn = document.getElementById('cerv-exp-all');
  if (expBtn) {
    expBtn.addEventListener('click', e => {
      e.stopPropagation();
      const clRows = [...tbody.querySelectorAll('tr[data-cl-id]')];
      const allOpen = clRows.every(r => r.dataset.open === '1');
      const next = allOpen ? '0' : '1';
      clRows.forEach(trCl => {
        trCl.dataset.open = next;
        const tog = trCl.querySelector('span[id$="-tog"]');
        if (tog) tog.textContent = next==='1' ? '−' : '+';
        const cid = trCl.dataset.clId;
        tbody.querySelectorAll(`[data-parent="${cid}"]`).forEach(r => { r.style.display = next==='1' ? '' : 'none'; });
      });
      expBtn.textContent = next==='1' ? '−' : '+';
    });
  }
  renderObjPanel('cerveza', lRows, 'cerveza-obj-panel');
}

// ── Bosque · Semanas pivot (colapsable por cluster) ───────────
function isoWeekKey(dateStr) {
  // Returns 'YYYY-WNN' for the ISO week containing dateStr
  // Parse as local time (not UTC) to avoid day-shift in negative-offset timezones
  const [yr, mo, dy] = dateStr.split('-').map(Number);
  const d = new Date(yr, mo - 1, dy);
  const thu = new Date(d);
  thu.setDate(d.getDate() - ((d.getDay() + 6) % 7) + 3); // Thursday of same week
  const year = thu.getFullYear();
  const jan4 = new Date(year, 0, 4);
  const week = 1 + Math.round(((thu - jan4) / 86400000 - 3 + ((jan4.getDay() + 6) % 7)) / 7);
  return `${year}-W${String(week).padStart(2,'0')}`;
}

function renderBosqueSemanasTabla(rows) {
  const tbl = document.getElementById('bosque-semanas-tbl');
  if (!tbl) return;
  tbl.innerHTML = '';

  const bRows = rows.filter(r => BOS_KEYS.includes(r.fa));
  if (!bRows.length) {
    tbl.innerHTML = '<tr><td style="color:#8b949e;padding:20px">Sin datos para el período seleccionado.</td></tr>';
    return;
  }

  // Semanas únicas ordenadas desc
  const semanas = [...new Set(bRows.map(r => isoWeekKey(r.f)))].sort().reverse();

  // tree: cl → nd → semana → sum(ce)
  const tree = {};
  bRows.forEach(r => {
    const wk = isoWeekKey(r.f);
    if (!tree[r.cl]) tree[r.cl] = {};
    if (!tree[r.cl][r.nd]) tree[r.cl][r.nd] = {};
    tree[r.cl][r.nd][wk] = (tree[r.cl][r.nd][wk] || 0) + r.ce;
  });

  // Totales globales por semana
  const colTot = {};
  let grandTotal = 0;
  semanas.forEach(wk => {
    const wkStr = wk;
    colTot[wkStr] = bRows.filter(r => isoWeekKey(r.f) === wkStr).reduce((s,r) => s + r.ce, 0);
    grandTotal += colTot[wkStr];
  });
  const maxVal = Math.max(1, ...Object.values(colTot));

  // Año-grupos para header fila 1
  const yearGroups = [];
  semanas.forEach(wk => {
    const y = wk.slice(0,4);
    if (yearGroups.length && yearGroups[yearGroups.length-1].year === y)
      yearGroups[yearGroups.length-1].count++;
    else
      yearGroups.push({ year: y, count: 1 });
  });

  const COL_W = '280px';
  const S_COL = `position:sticky;left:0;min-width:${COL_W};width:${COL_W};z-index:2;`;

  // ── THEAD ─────────────────────────────────────────────────────
  const thead = document.createElement('thead');

  // Fila 1: col-cluster (rowspan 2) + años + Total (rowspan 2)
  const tr1 = document.createElement('tr');
  const thCl = document.createElement('th');
  thCl.rowSpan = 2;
  thCl.style.cssText = `${S_COL}position:sticky;top:0;background:#161b22;z-index:7;color:#e8d5a3;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;padding:7px 12px;border-bottom:2px solid #3d2f0a;text-align:left;`;
  thCl.textContent = 'Clusterización / Cliente';
  tr1.appendChild(thCl);
  yearGroups.forEach(g => {
    const th = document.createElement('th');
    th.colSpan = g.count;
    th.style.cssText = 'position:sticky;top:0;background:#1a1608;z-index:4;text-align:center;color:#e8d5a3;font-size:11px;font-weight:700;letter-spacing:1px;padding:5px 8px;border-bottom:1px solid #3d2f0a;';
    th.textContent = g.year;
    tr1.appendChild(th);
  });
  const thTotHdr = document.createElement('th');
  thTotHdr.rowSpan = 2;
  thTotHdr.style.cssText = 'position:sticky;top:0;right:0;background:#1a1608;z-index:6;text-align:right;color:#e8d5a3;font-size:11px;font-weight:700;padding:7px 14px;border-bottom:2px solid #3d2f0a;border-left:2px solid #3d2f0a;white-space:nowrap;';
  thTotHdr.textContent = 'Total';
  tr1.appendChild(thTotHdr);
  thead.appendChild(tr1);

  // Fila 2: números de semana
  const tr2 = document.createElement('tr');
  semanas.forEach(wk => {
    const th = document.createElement('th');
    th.style.cssText = 'position:sticky;top:29px;background:#161b22;z-index:4;color:#c9a96e;font-size:11px;padding:4px 10px;text-align:right;white-space:nowrap;border-bottom:2px solid #3d2f0a;';
    th.textContent = parseInt(wk.slice(6), 10); // número de semana sin ceros
    tr2.appendChild(th);
  });
  thead.appendChild(tr2);
  tbl.appendChild(thead);

  // ── TBODY ─────────────────────────────────────────────────────
  const tbody = document.createElement('tbody');
  const sortedCl = Object.keys(tree).sort((a,b) => {
    const s = cl => semanas.reduce((t,wk) => t + Object.values(tree[cl]).reduce((tt,nd) => tt+(nd[wk]||0),0), 0);
    return s(b) - s(a);
  });

  sortedCl.forEach(cl => {
    const nds = Object.keys(tree[cl]).sort((a, b) => {
      const totA = semanas.reduce((s,wk) => s + (tree[cl][a][wk]||0), 0);
      const totB = semanas.reduce((s,wk) => s + (tree[cl][b][wk]||0), 0);
      return totB - totA;
    });
    const clId = 'sw_' + cl.replace(/[^a-z0-9]/gi, '_');

    // Totales del cluster por semana
    const clTotSem = {};
    let clTotAll = 0;
    semanas.forEach(wk => {
      clTotSem[wk] = nds.reduce((s, nd) => s + (tree[cl][nd][wk]||0), 0);
      clTotAll += clTotSem[wk];
    });

    // Fila cluster
    const trCl = document.createElement('tr');
    trCl.style.cursor = 'pointer';
    trCl.dataset.open = '0';

    const tdCl = document.createElement('td');
    tdCl.style.cssText = `${S_COL}background:#1a1608;color:#e8d5a3;font-size:11px;font-weight:700;padding:7px 12px;border-bottom:1px solid #21262d;text-align:left;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;`;
    tdCl.innerHTML = `<span id="${clId}-tog" style="display:inline-flex;align-items:center;justify-content:center;width:16px;height:16px;border:1px solid #3d2f0a;border-radius:3px;margin-right:8px;font-size:11px;font-weight:900;color:#e8d5a3;background:#2a1f08;vertical-align:middle;flex-shrink:0">+</span>${cl}`;
    trCl.appendChild(tdCl);

    semanas.forEach(wk => {
      const val = clTotSem[wk] || 0;
      const td = document.createElement('td');
      td.style.cssText = 'text-align:right;padding:7px 10px;font-size:11px;font-weight:700;border-bottom:1px solid #21262d;white-space:nowrap;font-variant-numeric:tabular-nums;';
      if (val > 0) {
        const alpha = 0.08 + (val / maxVal) * 0.62;
        td.style.background = `rgba(110,231,183,${alpha.toFixed(2)})`;
        td.style.color = alpha > 0.45 ? '#061a10' : '#e6edf3';
        td.textContent = val.toLocaleString('es-AR');
      } else {
        td.style.color = '#30363d';
        td.textContent = '—';
      }
      trCl.appendChild(td);
    });

    const tdClTot = document.createElement('td');
    tdClTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:7px 14px;font-size:11px;font-weight:800;color:#e8d5a3;background:#1a1608;border-bottom:1px solid #21262d;border-left:2px solid #3d2f0a;white-space:nowrap;font-variant-numeric:tabular-nums;';
    tdClTot.textContent = clTotAll.toLocaleString('es-AR');
    trCl.appendChild(tdClTot);

    trCl.addEventListener('click', () => {
      const isOpen = trCl.dataset.open === '1';
      trCl.dataset.open = isOpen ? '0' : '1';
      const tog = document.getElementById(clId + '-tog');
      if (tog) tog.textContent = isOpen ? '+' : '−';
      tbody.querySelectorAll(`tr[data-parent="${clId}"]`).forEach(tr => {
        tr.style.display = isOpen ? 'none' : '';
      });
    });
    tbody.appendChild(trCl);

    // Sub-filas clientes (ocultas por defecto)
    nds.forEach(nd => {
      let ndTot = 0;
      const trNd = document.createElement('tr');
      trNd.dataset.parent = clId;
      trNd.style.display = 'none';

      const tdNd = document.createElement('td');
      tdNd.style.cssText = `${S_COL}background:#161b22;color:#c9d1d9;font-size:11px;padding:5px 12px 5px 38px;border-bottom:1px solid #1c2128;text-align:left;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;`;
      tdNd.textContent = nd;
      trNd.appendChild(tdNd);

      semanas.forEach(wk => {
        const val = tree[cl][nd][wk] || 0;
        ndTot += val;
        const td = document.createElement('td');
        td.style.cssText = 'text-align:right;padding:5px 10px;font-size:11px;border-bottom:1px solid #1c2128;white-space:nowrap;font-variant-numeric:tabular-nums;';
        if (val > 0) {
          const alpha = 0.05 + (val / maxVal) * 0.5;
          td.style.background = `rgba(110,231,183,${alpha.toFixed(2)})`;
          td.style.color = alpha > 0.4 ? '#061a10' : '#e6edf3';
          td.textContent = val.toLocaleString('es-AR');
        } else {
          td.style.color = '#30363d';
          td.textContent = '—';
        }
        trNd.appendChild(td);
      });

      const tdNdTot = document.createElement('td');
      tdNdTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:5px 14px;font-size:11px;font-weight:600;color:#c9d1d9;background:#161b22;border-bottom:1px solid #1c2128;border-left:2px solid #21262d;white-space:nowrap;font-variant-numeric:tabular-nums;';
      tdNdTot.textContent = ndTot > 0 ? ndTot.toLocaleString('es-AR') : '—';
      trNd.appendChild(tdNdTot);

      tbody.appendChild(trNd);
    });
  });

  // Fila grand total
  const trT = document.createElement('tr');
  const tdTotLbl = document.createElement('td');
  tdTotLbl.style.cssText = `${S_COL}background:#1a1608;color:#e8d5a3;font-size:11px;font-weight:900;padding:9px 12px;border-top:2px solid #3d2f0a;text-align:left;text-transform:uppercase;letter-spacing:.5px;`;
  tdTotLbl.textContent = 'Total';
  trT.appendChild(tdTotLbl);
  semanas.forEach(wk => {
    const val = colTot[wk] || 0;
    const td = document.createElement('td');
    td.style.cssText = 'text-align:right;padding:9px 10px;font-size:11px;font-weight:800;color:#e8d5a3;background:#1a1608;border-top:2px solid #3d2f0a;white-space:nowrap;font-variant-numeric:tabular-nums;';
    td.textContent = val > 0 ? val.toLocaleString('es-AR') : '—';
    trT.appendChild(td);
  });
  const tdGrandTot = document.createElement('td');
  tdGrandTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:9px 14px;font-size:12px;font-weight:900;color:#e8d5a3;background:#1a1608;border-top:2px solid #3d2f0a;border-left:2px solid #3d2f0a;white-space:nowrap;font-variant-numeric:tabular-nums;';
  tdGrandTot.textContent = grandTotal.toLocaleString('es-AR');
  trT.appendChild(tdGrandTot);
  tbody.appendChild(trT);
  tbl.appendChild(tbody);
}

// ── Bosque · Canal/Cliente pivot (colapsable por cluster) ─────
function renderBosqueTabla(rows) {
  const tbl = document.getElementById('bosque-pivot-tbl');
  if (!tbl) return;
  tbl.innerHTML = '';

  const bRows = rows.filter(r => BOS_KEYS.includes(r.fa));
  if (!bRows.length) {
    tbl.innerHTML = '<tr><td style="color:#8b949e;padding:20px">Sin datos para el período seleccionado.</td></tr>';
    return;
  }

  // Meses únicos ordenados desc (más reciente a la izquierda)
  const meses = [...new Set(bRows.map(r => r.f.slice(0,7)))].sort().reverse();

  // tree: cl → nd → mes → sum(ce)
  const tree = {};
  bRows.forEach(r => {
    const m = r.f.slice(0,7);
    if (!tree[r.cl]) tree[r.cl] = {};
    if (!tree[r.cl][r.nd]) tree[r.cl][r.nd] = {};
    tree[r.cl][r.nd][m] = (tree[r.cl][r.nd][m] || 0) + r.ce;
  });

  // Totales globales por mes (para heatmap)
  const colTot = {};
  let grandTotal = 0;
  meses.forEach(m => {
    colTot[m] = bRows.filter(r => r.f.slice(0,7) === m).reduce((s,r) => s + r.ce, 0);
    grandTotal += colTot[m];
  });
  const maxVal = Math.max(1, ...Object.values(colTot));

  // Año-grupos para header fila 1
  const yearGroups = [];
  meses.forEach(m => {
    const y = m.slice(0,4);
    if (yearGroups.length && yearGroups[yearGroups.length-1].year === y)
      yearGroups[yearGroups.length-1].count++;
    else
      yearGroups.push({ year: y, count: 1 });
  });

  const MNAMES = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
  const COL_W = '280px';
  const S_COL = `position:sticky;left:0;min-width:${COL_W};width:${COL_W};z-index:2;`;

  // ── THEAD ─────────────────────────────────────────────────────
  const thead = document.createElement('thead');

  // Fila 1: col-cluster (rowspan 2) + años + Total (rowspan 2)
  const tr1 = document.createElement('tr');
  const thCl = document.createElement('th');
  thCl.rowSpan = 2;
  thCl.style.cssText = `${S_COL}position:sticky;top:0;background:#161b22;z-index:7;color:#e8d5a3;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;padding:7px 12px;border-bottom:2px solid #3d2f0a;text-align:left;`;
  thCl.textContent = 'Clusterización / Cliente';
  tr1.appendChild(thCl);
  yearGroups.forEach(g => {
    const th = document.createElement('th');
    th.colSpan = g.count;
    th.style.cssText = 'position:sticky;top:0;background:#1a1608;z-index:4;text-align:center;color:#e8d5a3;font-size:11px;font-weight:700;letter-spacing:1px;padding:5px 8px;border-bottom:1px solid #3d2f0a;';
    th.textContent = g.year;
    tr1.appendChild(th);
  });
  const thTotHdr = document.createElement('th');
  thTotHdr.rowSpan = 2;
  thTotHdr.style.cssText = 'position:sticky;top:0;right:0;background:#1a1608;z-index:6;text-align:right;color:#e8d5a3;font-size:11px;font-weight:700;padding:7px 14px;border-bottom:2px solid #3d2f0a;border-left:2px solid #3d2f0a;white-space:nowrap;';
  thTotHdr.textContent = 'Total';
  tr1.appendChild(thTotHdr);
  thead.appendChild(tr1);

  // Fila 2: meses
  const tr2 = document.createElement('tr');
  meses.forEach(m => {
    const th = document.createElement('th');
    th.style.cssText = 'position:sticky;top:29px;background:#161b22;z-index:4;color:#c9a96e;font-size:11px;padding:4px 10px;text-align:right;white-space:nowrap;border-bottom:2px solid #3d2f0a;';
    th.textContent = MNAMES[parseInt(m.slice(5,7),10)-1];
    tr2.appendChild(th);
  });
  thead.appendChild(tr2);
  tbl.appendChild(thead);

  // ── TBODY ─────────────────────────────────────────────────────
  const tbody = document.createElement('tbody');
  const sortedCl = Object.keys(tree).sort((a,b) => {
    const s = cl => meses.reduce((t,m) => t + Object.values(tree[cl]).reduce((tt,nd) => tt+(nd[m]||0),0), 0);
    return s(b) - s(a);
  });

  sortedCl.forEach(cl => {
    const nds = Object.keys(tree[cl]).sort((a, b) => {
      const totA = meses.reduce((s,m) => s + (tree[cl][a][m]||0), 0);
      const totB = meses.reduce((s,m) => s + (tree[cl][b][m]||0), 0);
      return totB - totA;
    });
    const clId = cl.replace(/[^a-z0-9]/gi, '_');

    // Totales del cluster por mes
    const clTotMes = {};
    let clTotAll = 0;
    meses.forEach(m => {
      clTotMes[m] = nds.reduce((s, nd) => s + (tree[cl][nd][m]||0), 0);
      clTotAll += clTotMes[m];
    });

    // ── Fila cluster (colapsable) ────────────────────────────
    const trCl = document.createElement('tr');
    trCl.style.cursor = 'pointer';
    trCl.dataset.open = '0';

    const tdCl = document.createElement('td');
    tdCl.style.cssText = `${S_COL}background:#1a1608;color:#e8d5a3;font-size:11px;font-weight:700;padding:7px 12px;border-bottom:1px solid #21262d;text-align:left;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;`;
    tdCl.innerHTML = `<span id="tog-${clId}" style="display:inline-flex;align-items:center;justify-content:center;width:16px;height:16px;border:1px solid #3d2f0a;border-radius:3px;margin-right:8px;font-size:11px;font-weight:900;color:#e8d5a3;background:#2a1f08;vertical-align:middle;flex-shrink:0">+</span>${cl}`;
    trCl.appendChild(tdCl);

    meses.forEach(m => {
      const val = clTotMes[m] || 0;
      const td = document.createElement('td');
      td.style.cssText = 'text-align:right;padding:7px 10px;font-size:11px;font-weight:700;border-bottom:1px solid #21262d;white-space:nowrap;font-variant-numeric:tabular-nums;';
      if (val > 0) {
        const alpha = 0.08 + (val / maxVal) * 0.62;
        td.style.background = `rgba(110,231,183,${alpha.toFixed(2)})`;
        td.style.color = alpha > 0.45 ? '#061a10' : '#e6edf3';
        td.textContent = val.toLocaleString('es-AR');
      } else {
        td.style.color = '#30363d';
        td.textContent = '—';
      }
      trCl.appendChild(td);
    });

    const tdClTot = document.createElement('td');
    tdClTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:7px 14px;font-size:11px;font-weight:800;color:#e8d5a3;background:#1a1608;border-bottom:1px solid #21262d;border-left:2px solid #3d2f0a;white-space:nowrap;font-variant-numeric:tabular-nums;';
    tdClTot.textContent = clTotAll.toLocaleString('es-AR');
    trCl.appendChild(tdClTot);

    trCl.addEventListener('click', () => {
      const isOpen = trCl.dataset.open === '1';
      trCl.dataset.open = isOpen ? '0' : '1';
      const tog = document.getElementById('tog-' + clId);
      if (tog) tog.textContent = isOpen ? '+' : '−';
      tbody.querySelectorAll(`tr[data-parent="${clId}"]`).forEach(tr => {
        tr.style.display = isOpen ? 'none' : '';
      });
    });
    tbody.appendChild(trCl);

    // ── Sub-filas de clientes (ocultas por defecto) ──────────
    nds.forEach(nd => {
      let ndTot = 0;
      const trNd = document.createElement('tr');
      trNd.dataset.parent = clId;
      trNd.style.display = 'none';

      const tdNd = document.createElement('td');
      tdNd.style.cssText = `${S_COL}background:#161b22;color:#c9d1d9;font-size:11px;padding:5px 12px 5px 38px;border-bottom:1px solid #1c2128;text-align:left;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;`;
      tdNd.textContent = nd;
      trNd.appendChild(tdNd);

      meses.forEach(m => {
        const val = tree[cl][nd][m] || 0;
        ndTot += val;
        const td = document.createElement('td');
        td.style.cssText = 'text-align:right;padding:5px 10px;font-size:11px;border-bottom:1px solid #1c2128;white-space:nowrap;font-variant-numeric:tabular-nums;';
        if (val > 0) {
          const alpha = 0.05 + (val / maxVal) * 0.5;
          td.style.background = `rgba(110,231,183,${alpha.toFixed(2)})`;
          td.style.color = alpha > 0.4 ? '#061a10' : '#e6edf3';
          td.textContent = val.toLocaleString('es-AR');
        } else {
          td.style.color = '#30363d';
          td.textContent = '—';
        }
        trNd.appendChild(td);
      });

      const tdNdTot = document.createElement('td');
      tdNdTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:5px 14px;font-size:11px;font-weight:600;color:#c9d1d9;background:#161b22;border-bottom:1px solid #1c2128;border-left:2px solid #21262d;white-space:nowrap;font-variant-numeric:tabular-nums;';
      tdNdTot.textContent = ndTot > 0 ? ndTot.toLocaleString('es-AR') : '—';
      trNd.appendChild(tdNdTot);

      tbody.appendChild(trNd);
    });
  });

  // ── Fila grand total ──────────────────────────────────────────
  const trT = document.createElement('tr');
  const tdTotLbl = document.createElement('td');
  tdTotLbl.style.cssText = `${S_COL}background:#1a1608;color:#e8d5a3;font-size:11px;font-weight:900;padding:9px 12px;border-top:2px solid #3d2f0a;text-align:left;text-transform:uppercase;letter-spacing:.5px;`;
  tdTotLbl.textContent = 'Total';
  trT.appendChild(tdTotLbl);
  meses.forEach(m => {
    const val = colTot[m] || 0;
    const td = document.createElement('td');
    td.style.cssText = 'text-align:right;padding:9px 10px;font-size:11px;font-weight:800;color:#e8d5a3;background:#1a1608;border-top:2px solid #3d2f0a;white-space:nowrap;font-variant-numeric:tabular-nums;';
    td.textContent = val > 0 ? val.toLocaleString('es-AR') : '—';
    trT.appendChild(td);
  });
  const tdGrandTot = document.createElement('td');
  tdGrandTot.style.cssText = 'position:sticky;right:0;text-align:right;padding:9px 14px;font-size:12px;font-weight:900;color:#e8d5a3;background:#1a1608;border-top:2px solid #3d2f0a;border-left:2px solid #3d2f0a;white-space:nowrap;font-variant-numeric:tabular-nums;';
  tdGrandTot.textContent = grandTotal.toLocaleString('es-AR');
  trT.appendChild(tdGrandTot);
  tbody.appendChild(trT);
  tbl.appendChild(tbody);
}

// ── Mapa Clientes: Nuevos vs Recurrentes (bubble) ────────────
function renderBosqueClientesMap(rows, rowsYoY) {
  const cur    = byKey(rows,    'nd');
  const prv    = byKey(rowsYoY, 'nd');
  const curSet = new Set(Object.keys(cur));
  const prvSet = new Set(Object.keys(prv));

  const nuevos = [], recurrentes = [], perdidos = [];
  curSet.forEach(k => {
    if (prvSet.has(k)) recurrentes.push({ nd:k, liCur:cur[k].li, liPrv:prv[k].li });
    else               nuevos.push({ nd:k, liCur:cur[k].li, liPrv:0 });
  });
  prvSet.forEach(k => {
    if (!curSet.has(k)) perdidos.push({ nd:k, liCur:0, liPrv:prv[k].li });
  });

  // Stats
  const statsEl = document.getElementById('bos-cli-stats');
  if (statsEl) {
    const segs = [
      { lbl:'Nuevos',      n:nuevos.length,      li:nuevos.reduce((s,c)=>s+c.liCur,0),      clr:'#6ee7b7' },
      { lbl:'Recurrentes', n:recurrentes.length,  li:recurrentes.reduce((s,c)=>s+c.liCur,0), clr:'#60a5fa' },
      { lbl:'Perdidos',    n:perdidos.length,      li:perdidos.reduce((s,c)=>s+c.liPrv,0),   clr:'#fca5a5' },
    ];
    statsEl.innerHTML = segs.map((s,i) => `
      ${i>0?'<div style="width:1px;background:#21262d;align-self:stretch"></div>':''}
      <div style="display:flex;flex-direction:column;gap:1px">
        <span style="font-size:9px;color:#6e7681;font-weight:700;letter-spacing:.5px;text-transform:uppercase">${s.lbl}</span>
        <span style="font-size:15px;font-weight:900;color:${s.clr};line-height:1">${s.n}</span>
        <span style="font-size:9px;color:#6e7681">${fmtNum(s.li,1)} L</span>
      </div>`).join('');
  }

  // Escala radios de burbujas
  const allVals = [...nuevos.map(c=>c.liCur), ...recurrentes.map(c=>c.liCur), ...perdidos.map(c=>c.liPrv)];
  const maxVal  = Math.max(...allVals, 1);
  const r = v => Math.max(4, Math.sqrt(v / maxVal) * 20);

  // Límite de ejes para la línea diagonal
  const maxAxis = Math.max(...recurrentes.map(c=>Math.max(c.liCur,c.liPrv)), 1) * 1.15;

  if (chartBosqueEvol) chartBosqueEvol.destroy();
  chartBosqueEvol = new Chart(document.getElementById('bos-chart-climap'), {
    type: 'bubble',
    data: {
      datasets: [
        {
          label: 'Recurrentes',
          data: recurrentes.map(c => ({ x:c.liPrv, y:c.liCur, r:r(c.liCur), nd:c.nd })),
          backgroundColor: 'rgba(96,165,250,.55)',
          borderColor: '#60a5fa', borderWidth: 1,
        },
        {
          label: 'Nuevos',
          data: nuevos.map(c => ({ x:0, y:c.liCur, r:r(c.liCur), nd:c.nd })),
          backgroundColor: 'rgba(110,231,183,.55)',
          borderColor: '#6ee7b7', borderWidth: 1,
        },
        {
          label: 'Perdidos',
          data: perdidos.map(c => ({ x:c.liPrv, y:0, r:r(c.liPrv), nd:c.nd })),
          backgroundColor: 'rgba(252,165,165,.45)',
          borderColor: '#fca5a5', borderWidth: 1,
        },
        // Diagonal de referencia (sin crecer ni caer)
        {
          label: '_ref',
          type: 'line',
          data: [{x:0,y:0},{x:maxAxis,y:maxAxis}],
          borderColor: 'rgba(110,118,129,.25)',
          borderWidth: 1, borderDash:[4,4],
          pointRadius: 0, fill: false,
        }
      ]
    },
    options: {
      responsive: true, maintainAspectRatio: false,
      plugins: {
        legend: {
          labels: { color:'#c9d1d9', font:{size:10}, boxWidth:8,
            filter: item => !item.text.startsWith('_'),
            generateLabels: chart =>
              Chart.defaults.plugins.legend.labels.generateLabels(chart)
                .filter(l => !l.text.startsWith('_'))
                .map(l => ({...l, fontColor:'#c9d1d9'}))
          }
        },
        tooltip: {
          callbacks: {
            label: ctx => {
              const nd  = ctx.raw.nd || '';
              const seg = ctx.dataset.label;
              if (seg === 'Nuevos')
                return ` ${nd}  ·  Nuevo  ·  ${fmtNum(ctx.raw.y,1)} L`;
              if (seg === 'Perdidos')
                return ` ${nd}  ·  Perdido  ·  ${fmtNum(ctx.raw.x,1)} L aa`;
              const pct = ctx.raw.x > 0
                ? ((ctx.raw.y-ctx.raw.x)/ctx.raw.x*100).toFixed(1)
                : null;
              const chg = pct !== null
                ? `  ${pct>=0?'+':''}${pct}% aa`
                : '';
              return ` ${nd}  ·  ${fmtNum(ctx.raw.y,1)} L${chg}`;
            }
          }
        }
      },
      scales: {
        x: {
          title: { display:true, text:'Litros año anterior', color:'#6e7681', font:{size:9} },
          ticks: { color:'#8b949e', font:{size:9},
            callback: v => v>=1000?(v/1000).toFixed(1)+'k':v },
          grid: { color:'rgba(48,54,61,.4)' },
          min: 0,
        },
        y: {
          title: { display:true, text:'Litros período actual', color:'#6e7681', font:{size:9} },
          ticks: { color:'#8b949e', font:{size:9},
            callback: v => v>=1000?(v/1000).toFixed(1)+'k':v },
          grid: { color:'rgba(48,54,61,.4)' },
          min: 0,
        }
      }
    }
  });
}

// ── Top Clientes (horizontal bar) ────────────────────────────
function renderBosqueTopClientes(rows) {
  const data   = byKey(rows, 'nd');
  const sorted = Object.entries(data)
    .sort((a,b) => b[1].li - a[1].li)
    .slice(0, 10);
  const totLi = sorted.reduce((s,[,v]) => s + v.li, 0);

  const labels = sorted.map(([k]) => k.length > 24 ? k.substring(0,23)+'…' : k);
  const vals   = sorted.map(([,v]) => v.li);
  const envs   = sorted.map(([,v]) => v.ce);

  const REDS = ['#e8d5a3','#dfc890','#d4bb7a','#caae64','#c0a14e',
                '#b69438','#ac8724','#a07a14','#946e10','#88620c'];

  if (chartBosqueClientes) chartBosqueClientes.destroy();
  chartBosqueClientes = new Chart(document.getElementById('bos-chart-clientes'), {
    type: 'bar',
    data: {
      labels,
      datasets: [{
        label: 'Litros',
        data: vals,
        backgroundColor: REDS.map(c => c + 'cc'),
        borderColor:     REDS,
        borderWidth: 1,
        borderRadius: 4,
      }]
    },
    options: {
      indexAxis: 'y',
      responsive: true, maintainAspectRatio: false,
      plugins: {
        legend: { display:false },
        tooltip: {
          callbacks: {
            label: ctx => {
              const pct = totLi > 0 ? (ctx.raw/totLi*100).toFixed(1) : '0';
              return ` ${fmtNum(ctx.raw,1)} L · ${fmtNum(envs[ctx.dataIndex])} env · ${pct}%`;
            }
          }
        }
      },
      scales: {
        x: {
          ticks: { color:'#8b949e', font:{size:10},
            callback: v => v>=1000?(v/1000).toFixed(1)+'k':v
          },
          grid: { color:'rgba(48,54,61,.4)' }
        },
        y: {
          ticks: { color:'#c9d1d9', font:{size:10} },
          grid:  { display:false }
        }
      }
    }
  });
}
